﻿import { useState, useEffect, useMemo, createElement } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { createTask, deleteEngagement, requestServiceDeleteOtp, updateEngagement, getEngagement } from '../../services/engagementService';
import StatusBadge from '../common/StatusBadge';
import DateInput from '../common/DateInput';
import { isEngagementOverdue } from '../../utils/serviceKpiFilters';
import { useStaffUsers } from '../../hooks/useStaffUsers';
import AddTaskModal from './AddTaskModal';
import { Plus, Pencil, FolderOpen, X, Trash2, Expand } from 'lucide-react';
import { useServiceTimer } from '../../hooks/useServiceTimer';
import { useElapsedTimer } from '../../hooks/useElapsedTimer';
import TimerHandoffModal from './TimerHandoffModal';
import { getTimeEntries } from '../../services/timeEntryService';

const ROW_STATUS_OPTIONS = ['not_started', 'in_progress', 'pending_info', 'review', 'completed', 'cancelled'];

function formatStatusLabel(s) {
  return s.replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
}

const engagementCellLinkStyle = {
  color: 'inherit',
  textDecoration: 'none',
  display: 'block',
};

/** Plain primary click: keep SPA behavior. Modified click / middle-click: browser follows `<Link>` (new tab, etc.). */
function engagementCellLinkClick(e, onPlainLeft) {
  if (e.button !== 0) return;
  if (e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) return;
  e.preventDefault();
  e.stopPropagation();
  onPlainLeft();
}

function ActionBtn({ icon, title, onClick }) {
  const [hover, setHover] = useState(false);
  return (
    <button
      type="button"
      title={title}
      onClick={onClick}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      style={{ ...actionBtn, background: hover ? 'var(--portal-primary-tint)' : 'var(--portal-bg)', borderColor: hover ? 'rgba(var(--portal-primary-rgb),0.4)' : '#E6E8F0', color: hover ? 'var(--portal-primary)' : '#64748b' }}
    >
      {createElement(icon, { size: 13 })}
    </button>
  );
}

/**
 * @param {object} props
 * @param {object[]} props.rows
 * @param {function} props.setAllServices
 * @param {boolean} props.canEditService
 * @param {boolean} props.canDeleteService
 * @param {string} [props.emptyMessage]
 * @param {(updated: object) => boolean} [props.shouldRemoveFromList] When true after update, row is removed from current page
 * @param {function} [props.onRowRemoved] Called when a row is removed from the list (delete or filter mismatch)
 * @param {string|number|null} [props.expandServiceId] Select this id in the side panel when it appears
 * @param {function} [props.onExpandConsumed]
 */
export default function ServicesEngagementTableBlock({
  rows,
  setAllServices,
  canEditService,
  canDeleteService,
  emptyMessage = 'No service engagements match your filters.',
  shouldRemoveFromList,
  onRowRemoved,
  expandServiceId,
  onExpandConsumed,
}) {
  const navigate = useNavigate();
  const [selectedService, setSelectedService] = useState(null);
  const [hoverRow, setHoverRow] = useState(null);
  const [showAddTask, setShowAddTask] = useState(false);
  const [showTimerModal, setShowTimerModal] = useState(false);
  const [pendingStartService, setPendingStartService] = useState(null);
  const [timerError, setTimerError] = useState('');
  const [serviceTimeEntries, setServiceTimeEntries] = useState([]);
  const [serviceToDelete, setServiceToDelete] = useState(null);
  const [serviceDeleteStep, setServiceDeleteStep] = useState('warn');
  const [deleteOtp, setDeleteOtp] = useState('');
  const [deleteOtpSent, setDeleteOtpSent] = useState(false);
  const [deleteErr, setDeleteErr] = useState('');
  const [deleteBusy, setDeleteBusy] = useState(false);
  const [requestingDeleteOtp, setRequestingDeleteOtp] = useState(false);
  const [hydratedAssigneeIds, setHydratedAssigneeIds] = useState(null);
  const { staffUsers } = useStaffUsers();
  const {
    activeTimer,
    busy: timerBusy,
    refreshActiveTimer,
    startForService,
    stopForService,
    saveStoppedEntry,
  } = useServiceTimer();

  const staffOptionsForTeam = useMemo(() => {
    if (!selectedService) return [];
    const assigneeUserIds = Array.isArray(selectedService.assigneeUserIds) ? selectedService.assigneeUserIds : [];
    const list = [...staffUsers];
    const seen = new Set(list.map((u) => String(u.id)));
    for (const uid of assigneeUserIds) {
      if (!seen.has(String(uid))) {
        seen.add(String(uid));
        list.push({ id: uid, name: `User #${uid}` });
      }
    }
    return list;
  }, [staffUsers, selectedService]);

  const assigneeNameById = useMemo(() => {
    const o = Object.create(null);
    for (const u of staffOptionsForTeam) o[u.id] = u.name;
    return o;
  }, [staffOptionsForTeam]);

  // Reset hydrated assignees when the selected service changes.
  useEffect(() => {
    setHydratedAssigneeIds(null);
  }, [selectedService?.id]);

  // When a service is selected from the list and its assigneeUserIds is empty
  // (e.g. legacy row where the field was not populated), fetch the full record
  // so that the Add Task modal can show the correct team-member options.
  useEffect(() => {
    if (!selectedService) return;
    const ids = Array.isArray(selectedService.assigneeUserIds) ? selectedService.assigneeUserIds : [];
    if (ids.length > 0) return; // already populated — no fetch needed
    let cancelled = false;
    getEngagement(selectedService.id)
      .then((full) => {
        if (!cancelled) {
          const freshIds = Array.isArray(full.assigneeUserIds) ? full.assigneeUserIds : [];
          setHydratedAssigneeIds(freshIds);
        }
      })
      .catch(() => {});
    return () => { cancelled = true; };
  }, [selectedService]);

  // Effective assignee IDs to pass to the Add Task modal: prefer hydrated, fall back to list data.
  const effectiveAssigneeIds = useMemo(() => {
    if (hydratedAssigneeIds !== null) return hydratedAssigneeIds;
    return Array.isArray(selectedService?.assigneeUserIds) ? selectedService.assigneeUserIds : [];
  }, [hydratedAssigneeIds, selectedService]);

  function applyRowUpdate(updated) {
    setAllServices((prev) => {
      if (shouldRemoveFromList?.(updated)) {
        onRowRemoved?.();
        return prev.filter((x) => x.id !== updated.id);
      }
      return prev.map((x) => (x.id === updated.id ? updated : x));
    });
  }

  useEffect(() => {
    if (expandServiceId == null) return;
    const found = rows.find((s) => String(s.id) === String(expandServiceId));
    if (found) {
      setSelectedService(found);
      onExpandConsumed?.();
      return undefined;
    }
    let cancelled = false;
    getEngagement(expandServiceId)
      .then((full) => {
        if (!cancelled) {
          setSelectedService(full);
          onExpandConsumed?.();
        }
      })
      .catch(() => onExpandConsumed?.());
    return () => { cancelled = true; };
  }, [expandServiceId, rows, onExpandConsumed]);

  useEffect(() => {
    if (!selectedService?.id) {
      setServiceTimeEntries([]);
      return;
    }
    getTimeEntries(selectedService.id).then(setServiceTimeEntries).catch(() => setServiceTimeEntries([]));
  }, [selectedService?.id]);

  function handleAddChildService() {
    if (!selectedService) return;
    const isChild = selectedService.masterServiceId && !selectedService.isMasterService;
    if (isChild) return;
    navigate('/services/new', {
      state: {
        parentServiceId: selectedService.id,
        parentServiceName: selectedService.serviceType || selectedService.type || `Service #${selectedService.id}`,
        parentIsMaster: selectedService.isMasterService,
        parentClientType: selectedService.clientType || 'contact',
        parentClientId: selectedService.clientId,
        parentClientName: selectedService.clientName,
        parentFinancialYear: selectedService.financialYear,
        returnUrl: `/services/${selectedService.id}`,
      },
    });
  }

  function handleAddTask(taskData) {
    if (!selectedService) return;
    createTask(selectedService.id, taskData)
      .then((updated) => {
        applyRowUpdate(updated);
        setSelectedService(updated);
      })
      .catch(() => {});
  }

  async function handleRowStatusChange(s, nextStatus) {
    if (!canEditService || nextStatus === s.status) return;
    if (nextStatus === 'cancelled') {
      const ok = window.confirm(`Mark this engagement as Cancelled for ${s.clientName}?`);
      if (!ok) return;
    }
    try {
      const updated = await updateEngagement(s.id, { status: nextStatus });
      applyRowUpdate(updated);
      setSelectedService((cur) => (cur && cur.id === updated.id ? updated : cur));
    } catch {
      /* optional toast */
    }
  }

  function closeServiceDeleteModal() {
    setServiceToDelete(null);
    setServiceDeleteStep('warn');
    setDeleteOtp('');
    setDeleteOtpSent(false);
    setDeleteErr('');
  }

  function openDeleteModal(s) {
    setServiceToDelete(s);
    setServiceDeleteStep('warn');
    setDeleteOtp('');
    setDeleteOtpSent(false);
    setDeleteErr('');
  }

  async function sendRowDeleteOtp() {
    if (!serviceToDelete) return;
    setRequestingDeleteOtp(true);
    setDeleteErr('');
    try {
      await requestServiceDeleteOtp(serviceToDelete.id);
      setDeleteOtpSent(true);
    } catch (e) {
      setDeleteErr(e.message || 'Failed to send OTP.');
    } finally {
      setRequestingDeleteOtp(false);
    }
  }

  async function confirmRowDelete() {
    if (!serviceToDelete) return;
    if (!deleteOtp.trim()) {
      setDeleteErr('Enter the superadmin OTP.');
      return;
    }
    setDeleteBusy(true);
    setDeleteErr('');
    try {
      await deleteEngagement(serviceToDelete.id, { superadminOtp: deleteOtp.trim() });
      setAllServices((prev) => prev.filter((x) => x.id !== serviceToDelete.id));
      onRowRemoved?.();
      setSelectedService((cur) => (cur && cur.id === serviceToDelete.id ? null : cur));
      closeServiceDeleteModal();
    } catch (e) {
      setDeleteErr(e.message || 'Delete failed.');
    } finally {
      setDeleteBusy(false);
    }
  }

  const serviceTasks = selectedService
    ? (Array.isArray(selectedService.tasks) ? selectedService.tasks : [])
    : [];
  const completedTasks = serviceTasks.filter((t) => t.status === 'done').length;
  const progress = serviceTasks.length ? Math.round((completedTasks / serviceTasks.length) * 100) : 0;
  const openTasksForTime = serviceTasks.filter((t) => t.id && t.status !== 'done');
  const drawerRunningHere = Boolean(activeTimer && String(activeTimer.serviceId) === String(selectedService?.id));
  const { label: drawerElapsedLabel } = useElapsedTimer(activeTimer?.startedAt, drawerRunningHere);

  async function refreshSelectedTimeEntries(serviceId = selectedService?.id) {
    if (!serviceId) return;
    const list = await getTimeEntries(serviceId);
    setServiceTimeEntries(list);
  }

  async function handleStartTimerForSelected() {
    if (!selectedService?.id) return;
    setTimerError('');
    if (activeTimer && String(activeTimer.serviceId) !== String(selectedService.id)) {
      setPendingStartService({ id: selectedService.id });
      setShowTimerModal(true);
      return;
    }
    if (activeTimer && String(activeTimer.serviceId) === String(selectedService.id)) {
      setTimerError('A timer is already running for this service.');
      return;
    }
    try {
      await startForService(selectedService.id, {});
      await refreshSelectedTimeEntries(selectedService.id);
    } catch (e) {
      const extra = e?.data?.active_timer;
      if (extra) {
        setPendingStartService({ id: selectedService.id });
        setShowTimerModal(true);
      } else {
        setTimerError(e.message || 'Could not start timer.');
      }
    }
  }

  function handleStopTimerForSelected() {
    if (!selectedService?.id || !activeTimer || String(activeTimer.serviceId) !== String(selectedService.id)) return;
    setTimerError('');
    setPendingStartService(null);
    setShowTimerModal(true);
  }

  return (
    <>
      {showAddTask && selectedService && (
        <AddTaskModal
          assigneeUserIds={effectiveAssigneeIds}
          staffUsers={staffUsers}
          onClose={() => setShowAddTask(false)}
          onSave={handleAddTask}
        />
      )}
      {serviceToDelete && (
        <div style={deleteEngOverlayStyle}>
          <div style={deleteEngModalStyle}>
            <div style={deleteEngHeaderStyle}>
              <span style={{ fontSize: 15, fontWeight: 700, color: '#b91c1c' }}>Delete service engagement</span>
              <button type="button" onClick={closeServiceDeleteModal} style={deleteEngCloseStyle}>✕</button>
            </div>
            <div style={{ padding: '16px 24px', display: 'flex', flexDirection: 'column', gap: 12 }}>
              {serviceDeleteStep === 'warn' ? (
                <>
                  <p style={{ fontSize: 13, color: '#334155', margin: 0 }}>
                    You are about to <strong>permanently delete</strong> the engagement for{' '}
                    <strong>{serviceToDelete.clientName}</strong> ({serviceToDelete.type || 'service'}, {serviceToDelete.financialYear || '—'}).
                  </p>
                  <p style={{ fontSize: 12, color: '#64748b', margin: 0 }}>
                    Assigned users can be notified by email. There is no way to undo this action. Continue only if this is intentional.
                  </p>
                </>
              ) : (
                <>
                  <button
                    type="button"
                    onClick={() => {
                      setServiceDeleteStep('warn');
                      setDeleteOtp('');
                      setDeleteOtpSent(false);
                      setDeleteErr('');
                    }}
                    style={{ ...deleteEngBtnSecondary, alignSelf: 'flex-start' }}
                  >
                    ← Back
                  </button>
                  <p style={{ fontSize: 13, color: '#334155', margin: 0 }}>
                    Request a superadmin OTP, then enter it to authorize deletion for{' '}
                    <strong>{serviceToDelete.clientName}</strong> — {serviceToDelete.type || 'service'}.
                  </p>
                  {deleteErr && <div style={{ color: '#dc2626', fontSize: 13 }}>{deleteErr}</div>}
                  <button type="button" style={deleteEngBtnSecondary} disabled={requestingDeleteOtp} onClick={sendRowDeleteOtp}>
                    {requestingDeleteOtp && !deleteOtpSent ? 'Sending…' : 'Request superadmin OTP'}
                  </button>
                  {deleteOtpSent && <span style={{ fontSize: 12, color: '#16a34a', fontWeight: 600 }}>Code sent</span>}
                  <label style={deleteEngLabelStyle}>
                    Superadmin OTP *
                    <input
                      type="text"
                      style={deleteEngInputStyle}
                      inputMode="numeric"
                      autoComplete="one-time-code"
                      value={deleteOtp}
                      onChange={(e) => setDeleteOtp(e.target.value.replace(/\s/g, ''))}
                    />
                  </label>
                </>
              )}
            </div>
            <div style={{ padding: '12px 24px 20px', display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
              {serviceDeleteStep === 'warn' ? (
                <>
                  <button type="button" onClick={closeServiceDeleteModal} style={deleteEngBtnSecondary}>Cancel</button>
                  <button type="button" style={{ ...deleteEngBtnPrimary, background: '#b91c1c' }} onClick={() => setServiceDeleteStep('otp')}>
                    Continue to OTP
                  </button>
                </>
              ) : (
                <>
                  <button type="button" onClick={closeServiceDeleteModal} style={deleteEngBtnSecondary}>Cancel</button>
                  <button type="button" disabled={deleteBusy} onClick={confirmRowDelete} style={{ ...deleteEngBtnPrimary, background: '#b91c1c' }}>
                    {deleteBusy ? 'Deleting…' : 'Delete engagement'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      )}
      <TimerHandoffModal
        open={showTimerModal}
        activeTimer={activeTimer}
        openTasks={openTasksForTime}
        onClose={() => {
          setShowTimerModal(false);
          setPendingStartService(null);
          refreshSelectedTimeEntries().catch(() => {});
          refreshActiveTimer().catch(() => {});
        }}
        pendingStartService={pendingStartService}
        onStopAndPrefill={(timer) => stopForService(timer.serviceId, timer.id)}
        onSubmitStopped={(entry, payload) => saveStoppedEntry(entry.serviceId, entry.id, payload)}
        onStartNext={(svc) => startForService(svc.id, {})}
      />
      <div style={{ display: 'grid', gridTemplateColumns: selectedService ? '1fr 380px' : '1fr', gap: 16 }}>
        <div style={tableCard}>
          <div style={{ overflowX: 'auto' }}>
            <table style={tableStyle}>
              <thead>
                <tr>
                  {['Client', 'Service', 'Period', 'Assigned To', 'Due Date', 'Fee', 'Status', 'Actions'].map((h) => (
                    <th key={h} style={thStyle}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {rows.map((s, idx) => {
                  const isActive = selectedService?.id === s.id;
                  const isHover = hoverRow === s.id;
                  const isOdd = idx % 2 === 0;
                  const isOverdue = isEngagementOverdue(s);
                  let rowBg = isOdd ? '#FAFBFD' : '#ffffff';
                  if (isActive) rowBg = 'var(--portal-primary-tint)';
                  else if (isHover) rowBg = '#FFF5EE';
                  const openEngagementPath = `/services/${s.id}`;
                  const toggleRowSelection = () => setSelectedService(isActive ? null : s);
                  return (
                    <tr
                      key={s.id}
                      style={{ ...trStyle, background: rowBg, cursor: 'pointer' }}
                      onClick={(e) => {
                        if (e.target.closest('a')) return;
                        if (e.target.closest('button')) return;
                        if (e.target.closest('select')) return;
                        toggleRowSelection();
                      }}
                      onMouseEnter={() => setHoverRow(s.id)}
                      onMouseLeave={() => setHoverRow(null)}
                    >
                      <td style={tdStyle}>
                        <Link
                          to={openEngagementPath}
                          style={engagementCellLinkStyle}
                          aria-label={`Open engagement: ${s.clientName}, ${s.type || 'service'}`}
                          onClick={(e) => engagementCellLinkClick(e, toggleRowSelection)}
                        >
                          <div style={clientCell}>
                            <div style={clientAvatar}>{s.clientName[0]}</div>
                            <span style={{ fontWeight: 600, color: '#0B1F3B' }}>{s.clientName}</span>
                          </div>
                        </Link>
                      </td>
                      <td style={tdStyle}>
                        <Link
                          to={openEngagementPath}
                          tabIndex={-1}
                          aria-hidden="true"
                          style={engagementCellLinkStyle}
                          onClick={(e) => engagementCellLinkClick(e, toggleRowSelection)}
                        >
                          <span style={serviceTag}>{s.type}</span>
                          {s.isMasterService && (
                            <span style={{
                              display: 'inline-block',
                              marginLeft: 6,
                              padding: '1px 7px',
                              fontSize: 10,
                              fontWeight: 700,
                              letterSpacing: '0.04em',
                              borderRadius: 4,
                              background: 'var(--portal-primary)',
                              color: '#fff',
                              verticalAlign: 'middle',
                              lineHeight: '16px',
                            }}>MASTER</span>
                          )}
                          {!s.isMasterService && s.masterServiceId && (
                            <span
                              title={s.masterServiceName ? `Linked to: ${s.masterServiceName}` : 'Linked to a master service'}
                              style={{
                                display: 'inline-block',
                                marginLeft: 6,
                                padding: '1px 7px',
                                fontSize: 10,
                                fontWeight: 600,
                                letterSpacing: '0.04em',
                                borderRadius: 4,
                                background: '#E2E8F0',
                                color: '#475569',
                                verticalAlign: 'middle',
                                lineHeight: '16px',
                                cursor: 'default',
                              }}>LINKED</span>
                          )}
                        </Link>
                      </td>
                      <td style={{ ...tdStyle, fontSize: 12, color: '#64748b' }}>
                        <Link
                          to={openEngagementPath}
                          tabIndex={-1}
                          aria-hidden="true"
                          style={engagementCellLinkStyle}
                          onClick={(e) => engagementCellLinkClick(e, toggleRowSelection)}
                        >
                          {s.relevantPeriodLabel || s.financialYear || '—'}
                        </Link>
                      </td>
                      <td style={tdStyle}>
                        <Link
                          to={openEngagementPath}
                          tabIndex={-1}
                          aria-hidden="true"
                          style={engagementCellLinkStyle}
                          onClick={(e) => engagementCellLinkClick(e, toggleRowSelection)}
                        >
                          {s.assignedTo}
                        </Link>
                      </td>
                      <td style={{ ...tdStyle, color: isOverdue ? '#ef4444' : '#334155', fontWeight: isOverdue ? 600 : 400 }}>
                        <Link
                          to={openEngagementPath}
                          tabIndex={-1}
                          aria-hidden="true"
                          style={{ ...engagementCellLinkStyle, color: 'inherit', fontWeight: 'inherit' }}
                          onClick={(e) => engagementCellLinkClick(e, toggleRowSelection)}
                        >
                          {s.dueDate}
                        </Link>
                      </td>
                      <td style={{ ...tdStyle, fontWeight: 600, color: '#0B1F3B' }}>
                        <Link
                          to={openEngagementPath}
                          tabIndex={-1}
                          aria-hidden="true"
                          style={{ ...engagementCellLinkStyle, fontWeight: 'inherit', color: 'inherit' }}
                          onClick={(e) => engagementCellLinkClick(e, toggleRowSelection)}
                        >
                          {s.feeAgreed != null && !Number.isNaN(Number(s.feeAgreed))
                            ? `₹${Number(s.feeAgreed).toLocaleString('en-IN')}`
                            : '—'}
                        </Link>
                      </td>
                      <td style={tdStyle} onClick={(e) => e.stopPropagation()}>
                        {canEditService ? (
                          <select
                            value={s.status}
                            onChange={(e) => handleRowStatusChange(s, e.target.value)}
                            style={rowStatusSelectStyle}
                            title="Status"
                            disabled={s.status === 'completed'}
                          >
                            {ROW_STATUS_OPTIONS.map((st) => (
                              <option key={st} value={st}>{formatStatusLabel(st)}</option>
                            ))}
                          </select>
                        ) : (
                          <StatusBadge status={s.status} />
                        )}
                      </td>
                      <td style={tdStyle} onClick={(e) => e.stopPropagation()}>
                        <div style={{ display: 'flex', gap: 4 }}>
                          <ActionBtn icon={Pencil} title="Manage" onClick={() => navigate(`/services/${s.id}`)} />
                          <ActionBtn icon={FolderOpen} title="View Files" onClick={() => navigate(`/services/${s.id}/files`)} />
                          {canDeleteService && (
                            <ActionBtn icon={Trash2} title="Delete" onClick={() => openDeleteModal(s)} />
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}

                {rows.length === 0 && (
                  <tr>
                    <td colSpan={8} style={{ padding: '32px', textAlign: 'center', color: '#94a3b8', fontSize: 13 }}>
                      {emptyMessage}
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          <div style={tableFooter}>
            <span>{rows.length} engagement{rows.length !== 1 ? 's' : ''}</span>
            <span style={{ fontSize: 11, color: '#94a3b8' }}>Live Data</span>
          </div>
        </div>

        {selectedService && (
          <div style={sidePanel}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 16 }}>
              <div>
                <div style={{ fontWeight: 700, fontSize: 15, color: '#0B1F3B' }}>{selectedService.type}</div>
                <div style={{ fontSize: 12, color: '#64748b', marginTop: 2 }}>{selectedService.clientName} · {selectedService.relevantPeriodLabel || selectedService.financialYear || '—'}</div>
              </div>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                <button
                  type="button"
                  title="Open in edit mode"
                  onClick={() => navigate(`/services/${selectedService.id}/edit`)}
                  style={openEditBtn}
                >
                  <Expand size={14} />
                </button>
                <button type="button" onClick={() => setSelectedService(null)} style={closeBtn}>
                  <X size={14} />
                </button>
              </div>
            </div>

            <div style={{ marginBottom: 18 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: '#64748b', marginBottom: 6 }}>
                <span style={{ fontWeight: 500 }}>Progress</span>
                <span style={{ fontWeight: 600, color: '#0B1F3B' }}>{completedTasks}/{serviceTasks.length} tasks</span>
              </div>
              <div style={progressTrack}>
                <div style={{ ...progressFill, width: `${progress}%` }} />
              </div>
              <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 4 }}>{progress}% complete</div>
            </div>

            <div style={{ marginBottom: 14, border: '1px solid #e2e8f0', borderRadius: 10, padding: 10, background: '#f8fafc' }}>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
                {activeTimer && String(activeTimer.serviceId) === String(selectedService.id) ? (
                  <button type="button" style={btnSecondary} disabled={timerBusy} onClick={handleStopTimerForSelected}>
                    {timerBusy ? 'Stopping...' : 'Stop timer'}
                  </button>
                ) : (
                  <button type="button" style={btnSecondary} disabled={timerBusy} onClick={handleStartTimerForSelected}>
                    {timerBusy ? 'Starting...' : 'Start timer'}
                  </button>
                )}
                {activeTimer ? (
                  <span style={{ fontSize: 11, color: '#64748b' }}>
                    Running: {activeTimer.clientName || `Service #${activeTimer.serviceId}`} {activeTimer.serviceType ? `(${activeTimer.serviceType})` : ''}
                  </span>
                ) : (
                  <span style={{ fontSize: 11, color: '#94a3b8' }}>No active timer</span>
                )}
                {drawerRunningHere ? (
                  <span style={{ fontSize: 11, color: '#0B1F3B', fontWeight: 700 }}>
                    Elapsed: {drawerElapsedLabel}
                  </span>
                ) : null}
              </div>
              {timerError ? <div style={{ fontSize: 11, color: '#dc2626', marginTop: 8 }}>{timerError}</div> : null}
            </div>

            {selectedService.notes && (
              <div style={{ marginBottom: 14, padding: '10px 12px', background: '#FFFBF5', border: '1px solid #FDE8D0', borderRadius: 8 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: '#C25A0A', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '0.04em' }}>Notes</div>
                <div style={{ fontSize: 12, color: '#334155', whiteSpace: 'pre-wrap', lineHeight: 1.5 }}>{selectedService.notes}</div>
              </div>
            )}

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
              <span style={{ fontWeight: 700, fontSize: 13, color: '#0B1F3B' }}>Tasks</span>
              <div style={{ display: 'flex', gap: 6 }}>
                <button type="button" style={btnSecondary} onClick={() => setShowAddTask(true)}><Plus size={12} /> Add Task</button>
                {!(selectedService.masterServiceId && !selectedService.isMasterService) && (
                  <button type="button" style={btnSecondary} onClick={handleAddChildService}><Plus size={12} /> Add Child Service</button>
                )}
              </div>
            </div>

            {serviceTasks.length === 0 && (
              <div style={{ color: '#94a3b8', fontSize: 13, textAlign: 'center', padding: '24px 0' }}>No tasks yet.</div>
            )}
            {serviceTasks.map((t) => {
              const taskEngagementPath = `/services/${selectedService.id}`;
              return (
                <Link
                  key={t.id}
                  to={taskEngagementPath}
                  style={{
                    ...taskRow,
                    textDecoration: 'none',
                    color: 'inherit',
                    display: 'block',
                    cursor: 'pointer',
                  }}
                  aria-label={`Open engagement for task: ${t.title}`}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: 8, flex: 1, minWidth: 0 }}>
                      <div style={{ ...taskDot, background: t.status === 'done' ? '#55B848' : t.status === 'in_progress' ? 'var(--portal-primary)' : '#e2e8f0', marginTop: 4, flexShrink: 0 }} />
                      <span style={{ fontSize: 13, fontWeight: t.status === 'done' ? 400 : 600, textDecoration: t.status === 'done' ? 'line-through' : 'none', color: t.status === 'done' ? '#94a3b8' : '#1e293b' }}>
                        {t.title}
                      </span>
                    </div>
                    <StatusBadge status={t.priority} />
                  </div>
                  <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 4, paddingLeft: 20 }}>
                    {[
                      t.assignedTo
                        || (t.assignedToUserId != null
                          ? (assigneeNameById[t.assignedToUserId] || `User #${t.assignedToUserId}`)
                          : null),
                      t.dueDate ? `Due: ${t.dueDate}` : null,
                    ].filter(Boolean).join(' · ')}
                  </div>
                </Link>
              );
            })}
            {serviceTimeEntries.length > 0 ? (
              <div style={{ marginTop: 14 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: '#0B1F3B', marginBottom: 6 }}>Recent time</div>
                {serviceTimeEntries.slice(0, 3).map((te) => (
                  <div key={te.id} style={{ fontSize: 11, color: '#64748b', marginBottom: 4 }}>
                    {te.workDate} - {te.durationMinutes} mins - {te.userName || 'User'}
                  </div>
                ))}
              </div>
            ) : null}
          </div>
        )}
      </div>
    </>
  );
}

