export default function Approvals() {
  const { user } = useAuth();
  const allowed =
    String(user?.role || '').toLowerCase() === ROLES.SUPER_ADMIN
    || String(user?.email || '').toLowerCase() === 'rahul@cagupta.in';

  const [filter, setFilter] = useState('all');
  const [timesheet, setTimesheet] = useState([]);
  const [associatePayoutAmendments, setAssociatePayoutAmendments] = useState([]);
  const [partner, setPartner] = useState([]);
  const [clientNames, setClientNames] = useState([]);
  const [clientEdits, setClientEdits] = useState([]);
  const [ledger, setLedger] = useState([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');
  const [busyKey, setBusyKey] = useState(null);

  const counts = useMemo(() => ({
    all: timesheet.length + associatePayoutAmendments.length + partner.length + clientNames.length + clientEdits.length + ledger.length,
    timesheet: timesheet.length,
    associate: associatePayoutAmendments.length,
    partner: partner.length,
    client_names: clientNames.length,
    client_edits: clientEdits.length,
    ledger: ledger.length,
  }), [timesheet, associatePayoutAmendments, partner, clientNames, clientEdits, ledger]);

  const load = useCallback(async () => {
    if (!allowed) return;
    setLoading(true);
    setErr('');
    try {
      const [ts, aff, part, names, edits, led] = await Promise.all([
        listPendingTimesheetOverflowRequests(),
        listPendingAssociatePayoutCycleAmendments(),
        listPendingPartnerPayoutCycleAmendments(),
        listPendingClientMasterNameChanges(),
        listPendingClientMasterEdits(),
        listPendingLedgerTxnChanges(),
      ]);
      setTimesheet(Array.isArray(ts) ? ts : []);
      setAssociatePayoutAmendments(Array.isArray(aff) ? aff : []);
      setPartner(Array.isArray(part) ? part : []);
      setClientNames(Array.isArray(names) ? names : []);
      setClientEdits(Array.isArray(edits) ? edits : []);
      setLedger(Array.isArray(led) ? led : []);
    } catch (e) {
      setErr(e.message || 'Failed to load approvals');
      setTimesheet([]);
      setAssociatePayoutAmendments([]);
      setPartner([]);
      setClientNames([]);
      setClientEdits([]);
      setLedger([]);
    } finally {
      setLoading(false);
    }
  }, [allowed]);

  useEffect(() => { load(); }, [load]);

  const items = useMemo(() => {
    const list = [];
    const include = (type) => filter === 'all' || filter === type;

    if (include('timesheet')) {
      timesheet.forEach((row) => list.push({ type: 'timesheet', id: row.id, row, _sort: sortKey(row) }));
    }
    if (include('associate')) {
      associatePayoutAmendments.forEach((row) => list.push({ type: 'associate', id: row.id, row, _sort: sortKey(row) }));
    }
    if (include('partner')) {
      partner.forEach((row) => list.push({ type: 'partner', id: row.id, row, _sort: sortKey(row) }));
    }
    if (include('client_names')) {
      clientNames.forEach((row) => {
        const id = row.approval_id || row.id;
        list.push({ type: 'client_names', id, row, _sort: sortKey(row) });
      });
    }
    if (include('client_edits')) {
      clientEdits.forEach((row) => {
        const id = row.approval_id || row.id;
        list.push({ type: 'client_edits', id, row, _sort: sortKey(row) });
      });
    }
    if (include('ledger')) {
      ledger.forEach((row) => {
        const id = row.approval_id || row.id;
        list.push({ type: 'ledger', id, row, _sort: sortKey(row) });
      });
    }

    return list.sort((a, b) => b._sort - a._sort);
  }, [filter, timesheet, associatePayoutAmendments, partner, clientNames, clientEdits, ledger]);

  async function runAction(key, fn) {
    setBusyKey(key);
    setErr('');
    try {
      await fn();
      await load();
      dispatchStaffNotificationsRefresh();
    } catch (e) {
      setErr(e.message || 'Action failed');
    } finally {
      setBusyKey(null);
    }
  }

  if (!allowed) {
    return (
      <div style={pageWrap}>
        <div style={pageHeader}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={iconWrap}><CheckSquare size={20} color="var(--portal-primary)" /></div>
            <div>
              <div style={{ fontSize: 20, fontWeight: 700, color: '#0B1F3B' }}>Approvals</div>
              <div style={{ fontSize: 13, color: '#64748b', marginTop: 2 }}>Super Admin access required.</div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={pageWrap}>
      <div style={pageHeader}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <div style={iconWrap}><CheckSquare size={20} color="var(--portal-primary)" /></div>
          <div>
            <div style={{ fontSize: 20, fontWeight: 700, color: '#0B1F3B' }}>Team Approvals</div>
            <div style={{ fontSize: 13, color: '#64748b', marginTop: 2 }}>
              {counts.all === 0
                ? 'No pending approval requests'
                : `${counts.all} pending request${counts.all === 1 ? '' : 's'} across all workflows`}
            </div>
          </div>
        </div>
      </div>

      <div style={toolbar}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#64748b', fontSize: 12, fontWeight: 600, marginRight: 4 }}>
          <Filter size={14} />
          Filter
        </div>
        {FILTER_OPTIONS.map((opt) => {
          const Icon = opt.icon;
          const isActive = filter === opt.key;
          const count = counts[opt.key] ?? 0;
          return (
            <button
              key={opt.key}
              type="button"
              onClick={() => setFilter(opt.key)}
              style={{
                display: 'flex', alignItems: 'center', gap: 6,
                padding: '8px 14px', borderRadius: 8,
                border: '1px solid', cursor: 'pointer',
                fontSize: 13, fontWeight: 600,
                background: isActive ? 'var(--portal-primary)' : '#fff',
                color: isActive ? '#fff' : '#475569',
                borderColor: isActive ? 'var(--portal-primary)' : '#E6E8F0',
              }}
            >
              {Icon && <Icon size={14} />}
              {opt.label}
              <span style={{
                fontSize: 11, fontWeight: 700, padding: '1px 7px', borderRadius: 10,
                background: isActive ? 'rgba(255,255,255,0.25)' : '#F1F5F9',
                color: isActive ? '#fff' : '#64748b',
              }}>
                {count}
              </span>
            </button>
          );
        })}
      </div>

      <div style={contentArea}>
        {loading && <div style={emptyState}>Loading approvals...</div>}
        {!loading && err && (
          <div style={errorBanner}>
            <AlertCircle size={14} /> {err}
          </div>
        )}
        {!loading && !err && items.length === 0 && (
          <div style={emptyState}>
            {filter === 'all'
              ? 'No pending approval requests.'
              : `No pending ${FILTER_OPTIONS.find((o) => o.key === filter)?.label?.toLowerCase() || ''} requests.`}
          </div>
        )}
        {!loading && !err && items.length > 0 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {items.map((item) => {
              const key = makeBusyKey(item.type, item.id);
              const busy = busyKey === key;

              if (item.type === 'timesheet') {
                return (
                  <OverflowCard
                    key={key}
                    row={item.row}
                    busy={busy}
                    onApprove={(id, modifyMin) => runAction(key, async () => {
                      const body = {};
                      if (modifyMin) {
                        const n = parseInt(String(modifyMin), 10);
                        if (Number.isFinite(n) && n > 0) body.approved_duration_minutes = n;
                      }
                      await approveTimesheetOverflowRequest(id, body);
                    })}
                    onReject={(id, reason) => runAction(key, () => rejectTimesheetOverflowRequest(id, reason))}
                  />
                );
              }

              if (item.type === 'associate' || item.type === 'partner') {
                const approveFn = item.type === 'associate'
                  ? approveAssociatePayoutCycleAmendment
                  : approvePartnerPayoutCycleAmendment;
                const rejectFn = item.type === 'associate'
                  ? rejectAssociatePayoutCycleAmendment
                  : rejectPartnerPayoutCycleAmendment;
                return (
                  <PayoutAmendmentCard
                    key={key}
                    kind={item.type}
                    row={item.row}
                    busy={busy}
                    onApprove={(id) => runAction(key, () => approveFn(id))}
                    onReject={(id, reason) => runAction(key, () => rejectFn(id, reason))}
                  />
                );
              }

              if (item.type === 'ledger') {
                return (
                  <LedgerTxnChangeCard
                    key={key}
                    row={item.row}
                    busy={busy}
                    onApprove={(id, decisionNotes) => runAction(key, async () => {
                      const body = {};
                      if (decisionNotes?.trim()) body.decision_notes = decisionNotes.trim();
                      await approveLedgerTxnChange(id, body);
                    })}
                    onReject={(id, reason) => runAction(key, () => rejectLedgerTxnChange(id, reason))}
                  />
                );
              }

              if (item.type === 'client_edits') {
                return (
                  <ClientMasterEditCard
                    key={key}
                    row={item.row}
                    busy={busy}
                    onApprove={(id, decisionNotes) => runAction(key, async () => {
                      const body = {};
                      if (decisionNotes?.trim()) body.decision_notes = decisionNotes.trim();
                      await approveClientMasterEdit(id, body);
                    })}
                    onReject={(id, reason) => runAction(key, () => rejectClientMasterEdit(id, reason))}
                  />
                );
              }

              return (
                <ClientMasterNameCard
                  key={key}
                  row={item.row}
                  busy={busy}
                  onApprove={(id, decisionNotes) => runAction(key, async () => {
                    const body = {};
                    if (decisionNotes?.trim()) body.decision_notes = decisionNotes.trim();
                    await approveClientMasterNameChange(id, body);
                  })}
                  onReject={(id, reason) => runAction(key, () => rejectClientMasterNameChange(id, reason))}
                />
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

