import { useCallback, useEffect, useState } from 'react';
import { useAuth } from '../../../auth/AuthContext';
import { ROLES } from '../../../constants/roles';
import { SUPER_ADMIN_EMAIL } from '../../../constants/config';
import {
  listPendingAssociatePayoutCycleAmendments,
  approveAssociatePayoutCycleAmendment,
  rejectAssociatePayoutCycleAmendment,
} from '../../../services/associatePayoutCycleService';

const btnPrimary = { padding: '8px 14px', borderRadius: 8, border: 'none', background: 'var(--portal-primary)', color: '#fff', fontWeight: 600, cursor: 'pointer', fontSize: 13 };
const btnGhost = { padding: '8px 14px', borderRadius: 8, border: '1px solid #e2e8f0', background: '#fff', fontWeight: 600, cursor: 'pointer', fontSize: 13 };

function parseAdj(raw) {
  if (raw == null) return [];
  if (Array.isArray(raw)) return raw;
  try {
    const j = typeof raw === 'string' ? JSON.parse(raw) : raw;
    return Array.isArray(j) ? j : [];
  } catch {
    return [];
  }
}

export default function AssociatePayoutCycleAmendmentApprovals() {
  const { user } = useAuth();
  const allowed =
    String(user?.role || '').toLowerCase() === ROLES.SUPER_ADMIN
    || String(user?.email || '').toLowerCase() === String(SUPER_ADMIN_EMAIL).toLowerCase();

  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState('');
  const [busyId, setBusyId] = useState(null);
  const [rejectReason, setRejectReason] = useState('');

  const load = useCallback(() => {
    if (!allowed) return;
    setLoading(true);
    setErr('');
    listPendingAssociatePayoutCycleAmendments()
      .then(setRows)
      .catch((e) => {
        setErr(e.message || 'Failed to load');
        setRows([]);
      })
      .finally(() => setLoading(false));
  }, [allowed]);

  useEffect(() => {
    load();
  }, [load]);

  async function onApprove(id) {
    setBusyId(id);
    setErr('');
    try {
      await approveAssociatePayoutCycleAmendment(id);
      await load();
    } catch (e) {
      setErr(e.message || 'Approve failed');
    } finally {
      setBusyId(null);
    }
  }

  async function onReject(id) {
    const reason = window.prompt('Rejection reason (required):', rejectReason);
    if (reason == null || !String(reason).trim()) {
      return;
    }
    setBusyId(id);
    setErr('');
    try {
      await rejectAssociatePayoutCycleAmendment(id, String(reason).trim());
      setRejectReason('');
      await load();
    } catch (e) {
      setErr(e.message || 'Reject failed');
    } finally {
      setBusyId(null);
    }
  }

  if (!allowed) {
    return (
      <div style={{ padding: 24 }}>
        <h1 style={{ fontSize: 18 }}>Associate payout amendments</h1>
        <p style={{ color: '#64748b' }}>Super Admin only.</p>
      </div>
    );
  }

  return (
    <div style={{ padding: 24, maxWidth: 900 }}>
      <h1 style={{ fontSize: 20, marginBottom: 8 }}>Associate payout cycle amendments</h1>
      <p style={{ fontSize: 13, color: '#64748b', marginBottom: 20 }}>
        Approving applies Accounts&apos; proposed commission amounts and <strong>finalises</strong> the cycle in one step (PR4).
      </p>
      <button type="button" style={btnGhost} onClick={load} disabled={loading}>Refresh</button>

      {err && (
        <div style={{ marginTop: 12, padding: 12, background: '#fef2f2', color: '#b91c1c', borderRadius: 8 }}>{err}</div>
      )}

      {loading && <p style={{ color: '#64748b', marginTop: 12 }}>Loading…</p>}

      {!loading && rows.length === 0 && (
        <p style={{ color: '#64748b', marginTop: 12 }}>No pending amendments.</p>
      )}

      {!loading && rows.map((r) => {
        const adj = parseAdj(r.adjustments_json);
        return (
          <div
            key={r.id}
            style={{
              border: '1px solid #E6E8F0',
              borderRadius: 12,
              padding: 16,
              marginTop: 12,
              background: '#fff',
            }}
          >
            <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 6 }}>
              Amendment #{r.id} · Cycle #{r.associate_payout_cycle_id}
            </div>
            <div style={{ fontSize: 13, color: '#475569', lineHeight: 1.5 }}>
              <div>Period: {r.period_start} → {r.period_end} ({r.cycle_anchor})</div>
              <div>Requested by: {r.requested_by_name || r.requested_by_user_id}</div>
            </div>
            <div style={{ marginTop: 10, fontSize: 12, fontFamily: 'monospace', background: '#f8fafc', padding: 10, borderRadius: 8, overflowX: 'auto' }}>
              {adj.map((a) => (
                <div key={a.commission_accrual_id}>
                  accrual {a.commission_accrual_id} → ₹{Number(a.amount_final).toFixed(2)}
                  {a.note ? ` (${a.note})` : ''}
                </div>
              ))}
            </div>
            <div style={{ display: 'flex', gap: 10, marginTop: 14 }}>
              <button
                type="button"
                style={btnPrimary}
                disabled={busyId === r.id}
                onClick={() => onApprove(r.id)}
              >
                {busyId === r.id ? '…' : 'Approve & finalise'}
              </button>
              <button
                type="button"
                style={btnGhost}
                disabled={busyId === r.id}
                onClick={() => onReject(r.id)}
              >
                Reject
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

﻿import { useMemo, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../../auth/AuthContext';
import { getDashboardStats } from '../services/dashboardService';
import { getEngagements } from '../../../services/engagementService';
import { getInvoices } from '../../../services/invoiceService';
import { getAppointments } from '../../../services/appointmentService';
import StatusBadge from '../../../components/common/StatusBadge';
import { formatRupeeKpiLakhAbbrev } from '../../../utils/indianRupeeKpi';

const METRIC_CARD_CONFIG = [
  { key: 'activeClients', label: 'Active Clients', icon: '👥', color: '#2563eb', bg: '#EFF6FF', to: '/clients/contacts' },
  { key: 'activeServices', label: 'Active Services', icon: '📋', color: '#7c3aed', bg: '#F5F3FF', to: '/services' },
  { key: 'unbilledServices', label: 'Unbilled (due)', icon: '🧾', color: '#c2410c', bg: '#FFF7ED', sub: 'billing open — raise invoice', to: '/invoices?tab=service_billing' },
  { key: 'pendingTasks', label: 'Pending Tasks', icon: '✅', color: '#d97706', bg: '#FFFBEB', sub: 'across all engagements', to: '/services' },
  { key: 'outstandingAmount', label: 'Outstanding Amount', icon: '💰', color: '#dc2626', bg: '#FEF2F2', sub: 'receivables by group', to: '/invoices/ledgers?tab=recovery_list' },
  { key: 'documentsThisMonth', label: 'Documents This Month', icon: '📂', color: '#0891b2', bg: '#ECFEFF', to: '/documents' },
  { key: 'appointmentsToday', label: 'Appointments Today', icon: '📅', color: '#16a34a', bg: '#F0FDF4', to: '/calendar' },
];

const StatCard = ({ icon, label, value, sub, color, bg, to, onNavigate, valueTooltip, valueNowrap }) => (
  <button
    type="button"
    onClick={() => onNavigate(to)}
    style={{ ...statCardStyle, cursor: 'pointer' }}
    title={`Open ${label}`}
    aria-label={`${label}: ${valueTooltip || value}`}
  >
    <div style={{ width: 48, height: 48, borderRadius: 12, background: bg || 'var(--portal-bg)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, flexShrink: 0 }}>{icon}</div>
    <div style={{ flex: 1, minWidth: 0, textAlign: 'left' }}>
      <div style={{ fontSize: 13, color: '#64748b', marginBottom: 4, overflowWrap: 'break-word' }}>{label}</div>
      <div
        style={{
          fontSize: 26,
          fontWeight: 700,
          color: '#1e293b',
          lineHeight: 1.15,
          minWidth: 0,
          ...(valueNowrap
            ? { whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }
            : { overflowWrap: 'anywhere', wordBreak: 'break-word' }),
        }}
      >
        {valueTooltip ? <span title={valueTooltip}>{value}</span> : value}
      </div>
      {sub && (
        <div style={{ fontSize: 11, color: color, marginTop: 4, fontWeight: 600, overflowWrap: 'break-word' }}>{sub}</div>
      )}
    </div>
  </button>
);

const QUICK_ACTIONS = [
  { label: '➕ New Client',        path: '/clients/contacts/new' },
  { label: '📋 New Service',       path: '/services/new' },
  { label: '📄 Upload Document',   path: '/documents' },
  { label: '🧾 Raise Invoice',     path: '/invoices' },
  { label: '📅 Book Appointment',  path: '/calendar' },
  { label: '🔍 Search',            path: '/search' },
];

export default function Dashboard() {
  const navigate = useNavigate();
  const { hasPermission } = useAuth();
  const canViewTimesheetReports = hasPermission('services.view');

  const [stats, setStats]           = useState({ activeClients: '—', activeServices: '—', unbilledServices: 0, pendingTasks: '—', totalOutstanding: 0, documentsThisMonth: '—', appointmentsToday: '—' });
  const [tasks, setTasks]           = useState([]);
  const [invoices, setInvoices]     = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading]       = useState(true);

  useEffect(() => {
    setLoading(true);
    Promise.all([
      getDashboardStats().catch(() => ({})),
      getEngagements().catch(() => []),
      getInvoices().catch(() => []),
      getAppointments().catch(() => []),
    ]).then(([s, eng, inv, appt]) => {
      setStats(s);
      // Non-completed tasks sorted by due date, top 4
      const pending = eng
        .filter(e => e.status !== 'completed')
        .flatMap(e => (e.tasks || []).filter(t => t.status !== 'done').map(t => ({ ...t, clientName: e.clientName })))
        .sort((a, b) => (a.dueDate || '').localeCompare(b.dueDate || ''))
        .slice(0, 4);
      setTasks(pending);
      // Pending invoices
      setInvoices(inv.filter(i => ['sent', 'partially_paid', 'overdue'].includes(i.status)));
      // Upcoming / scheduled appointments
      setAppointments(appt.filter(a => a.status !== 'cancelled').slice(0, 5));
    }).finally(() => setLoading(false));
  }, []);

  const outstandingDisplay = useMemo(() => {
    if (loading) return { value: '…', valueTooltip: undefined, valueNowrap: false };
    if (typeof stats.totalOutstanding !== 'number') {
      return { value: stats.totalOutstanding, valueTooltip: undefined, valueNowrap: false };
    }
    const { short, full, abbreviated } = formatRupeeKpiLakhAbbrev(stats.totalOutstanding);
    return {
      value: short,
      valueTooltip: abbreviated ? full : undefined,
      valueNowrap: abbreviated,
    };
  }, [loading, stats.totalOutstanding]);

  const metricValues = useMemo(() => ({
    activeClients: loading ? '…' : stats.activeClients,
    activeServices: loading ? '…' : stats.activeServices,
    unbilledServices: loading ? '…' : (typeof stats.unbilledServices === 'number' ? String(stats.unbilledServices) : (stats.unbilledServices ?? '0')),
    pendingTasks: loading ? '…' : stats.pendingTasks,
    outstandingAmount: outstandingDisplay.value,
    documentsThisMonth: loading ? '…' : stats.documentsThisMonth,
    appointmentsToday: loading ? '…' : stats.appointmentsToday,
  }), [loading, stats, outstandingDisplay.value]);

  const outstandingCardExtras =
    metricValues.outstandingAmount === '…'
      ? {}
      : { valueTooltip: outstandingDisplay.valueTooltip, valueNowrap: outstandingDisplay.valueNowrap };

  const handleMetricNavigate = (to) => {
    if (to) {
      navigate(to);
      return;
    }
    navigate('/dashboard/metrics/general');
  };

  return (
    <div style={{ padding: 24, background: 'var(--portal-bg)', minHeight: '100%' }}>
      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px,1fr))', gap: 16, marginBottom: 28 }}>
        {METRIC_CARD_CONFIG.map((card) => (
          <StatCard
            key={card.key}
            icon={card.icon}
            label={card.label}
            value={metricValues[card.key]}
            sub={card.sub}
            color={card.color}
            bg={card.bg}
            to={card.to}
            onNavigate={handleMetricNavigate}
            {...(card.key === 'outstandingAmount' ? outstandingCardExtras : {})}
          />
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        {/* Pending / overdue tasks */}
        <section style={cardStyle}>
          <h3 style={cardTitle}>⚠️ Pending & Overdue Tasks</h3>
          <table style={tableStyle}>
            <thead>
              <tr>{['Task', 'Client', 'Due', 'Priority'].map(h => <th key={h} style={thStyle}>{h}</th>)}</tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={4} style={{ ...tdStyle, color: '#94a3b8', textAlign: 'center', padding: 20 }}>Loading…</td></tr>
              ) : tasks.length === 0 ? (
                <tr><td colSpan={4} style={{ ...tdStyle, color: '#94a3b8', textAlign: 'center', padding: 20 }}>No pending tasks.</td></tr>
              ) : tasks.map((t, i) => (
                <tr key={t.id || i} style={trStyle}>
                  <td style={tdStyle}>{t.title}</td>
                  <td style={tdStyle}>{t.clientName || t.assignedTo}</td>
                  <td style={tdStyle}>{t.dueDate}</td>
                  <td style={tdStyle}><StatusBadge status={t.priority} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>

        {/* Pending invoices */}
        <section style={cardStyle}>
          <h3 style={cardTitle}>🧾 Pending Invoices</h3>
          <table style={tableStyle}>
            <thead>
              <tr>{['Invoice #', 'Client', 'Amount', 'Status'].map(h => <th key={h} style={thStyle}>{h}</th>)}</tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={4} style={{ ...tdStyle, color: '#94a3b8', textAlign: 'center', padding: 20 }}>Loading…</td></tr>
              ) : invoices.length === 0 ? (
                <tr><td colSpan={4} style={{ ...tdStyle, color: '#94a3b8', textAlign: 'center', padding: 20 }}>No pending invoices.</td></tr>
              ) : invoices.map(inv => (
                <tr key={inv.id} style={trStyle}>
                  <td style={tdStyle}>{inv.invoiceNumber}</td>
                  <td style={tdStyle}>{inv.clientName}</td>
                  <td style={tdStyle}>₹{(inv.totalAmount - inv.amountPaid).toLocaleString('en-IN')}</td>
                  <td style={tdStyle}><StatusBadge status={inv.status} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>

        {/* Upcoming appointments */}
        <section style={cardStyle}>
          <h3 style={cardTitle}>📅 Upcoming Appointments</h3>
          {loading ? (
            <div style={{ color: '#94a3b8', padding: '16px 0', fontSize: 13 }}>Loading…</div>
          ) : appointments.length === 0 ? (
            <div style={{ color: '#94a3b8', padding: '16px 0', fontSize: 13 }}>No upcoming appointments.</div>
          ) : appointments.map(a => (
            <div key={a.id} style={{ padding: '10px 0', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 13 }}>{a.clientName}</div>
                <div style={{ fontSize: 12, color: '#64748b' }}>{a.subject || a.title} — {a.date || a.eventDate} {a.startTime} ({a.mode || a.eventType})</div>
              </div>
              <StatusBadge status={a.status} />
            </div>
          ))}
        </section>

        {/* Quick actions */}
        <section style={cardStyle}>
          <h3 style={cardTitle}>⚡ Quick Actions</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginTop: 8 }}>
            {QUICK_ACTIONS.map(({ label, path }) => (
              <button key={label} style={actionBtn} onClick={() => navigate(path)}>{label}</button>
            ))}
            {canViewTimesheetReports && (
              <button
                type="button"
                style={{ ...actionBtn, gridColumn: '1 / -1', borderColor: '#FDBA74', background: '#FFF7ED', fontWeight: 600 }}
                onClick={() => navigate('/reports/timesheets/shift-target')}
              >
                🕐 Staff punch vs target (deficit and overtime)
              </button>
            )}
          </div>
        </section>
      </div>
    </div>
  );
}

const cardStyle = { background: '#fff', borderRadius: 14, padding: 20, boxShadow: '0 1px 4px rgba(0,0,0,.06)', border: '1px solid #E6E8F0' };
const statCardStyle = {
  width: '100%',
  minWidth: 0,
  maxWidth: '100%',
  boxSizing: 'border-box',
  background: '#fff',
  borderRadius: 14,
  padding: '20px',
  boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
  border: '1px solid #E6E8F0',
  display: 'flex',
  alignItems: 'center',
  gap: 16,
};
const cardTitle = { margin: '0 0 14px 0', fontSize: 15, fontWeight: 700, color: '#1e293b' };
const tableStyle = { width: '100%', borderCollapse: 'collapse', fontSize: 13 };
const thStyle = { textAlign: 'left', padding: '8px 10px', color: '#64748b', fontWeight: 600, fontSize: 11, borderBottom: '1px solid #F0F2F8', background: '#F8FAFC', textTransform: 'uppercase', letterSpacing: '0.04em' };
const tdStyle = { padding: '9px 10px', color: '#334155', verticalAlign: 'middle' };
const trStyle = { borderBottom: '1px solid var(--portal-bg)' };
const actionBtn = { padding: '9px 12px', background: 'var(--portal-bg)', border: '1px solid #E6E8F0', borderRadius: 10, cursor: 'pointer', fontSize: 13, textAlign: 'left', fontWeight: 500, color: '#334155' };

