import { useState, useEffect, useCallback } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { GoogleOAuthProvider, GoogleLogin } from '@react-oauth/google';
import { useMsal } from '@azure/msal-react';
import { Briefcase, Handshake, UserCircle, Users } from 'lucide-react';
import logoUrl from '../../../assets/cropped_logo.png';
import { useAuth } from '../../../auth/AuthContext';
import {
  PORTAL_META as SHARED_PORTAL_META,
  normalizePortalSlug,
  portalMismatchMessage,
  homeRouteForRole,
} from '@cagupta/shared-constants';
import {
  loginWithGoogle,
  loginWithPassword,
  requestEmailOtp,
  verifyEmailOtp,
} from '../services/authService';

const GOOGLE_CLIENT_ID = import.meta.env.VITE_GOOGLE_CLIENT_ID || '';
const MARKETING_URL = import.meta.env.VITE_MARKETING_URL || 'https://carahulgupta.in';

const PORTAL_ICONS = {
  Users,
  Handshake,
  UserCircle,
  Briefcase,
};

const PORTAL_META = Object.fromEntries(
  Object.entries(SHARED_PORTAL_META).map(([key, meta]) => [
    key,
    { ...meta, Icon: PORTAL_ICONS[meta.iconKey] },
  ]),
);

const MOCK_GOOGLE_CREDENTIAL =
  'mock-google-credential.' +
  btoa(JSON.stringify({ name: 'Google User', email: 'user@gmail.com' })) +
  '.sig';

function isValidEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function homeForUser(user) {
  return homeRouteForRole(user?.role);
}

export default function LoginPage() {
  const { isAuthenticated, login, user } = useAuth();
  const navigate = useNavigate();
  const { instance: msalInstance } = useMsal();
  const [searchParams] = useSearchParams();

  const urlPortal = normalizePortalSlug(searchParams.get('portal'));
  const portalFromUrl = urlPortal;
  const portalLocked = Boolean(portalFromUrl);

  const [loginPortal, setLoginPortalState] = useState(
    () => portalFromUrl || sessionStorage.getItem('login_portal') || 'staff'
  );
  const setLoginPortal = (p) => {
    sessionStorage.setItem('login_portal', p);
    setLoginPortalState(p);
  };

  useEffect(() => {
    if (portalFromUrl && portalFromUrl !== loginPortal) {
      sessionStorage.setItem('login_portal', portalFromUrl);
      setLoginPortalState(portalFromUrl);
    }
  }, [portalFromUrl, loginPortal]);

  // Step 1 state
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [clientIdentifier, setClientIdentifier] = useState('');

  // OTP step state
  const [otpStep, setOtpStep] = useState(false);
  const [maskedEmail, setMaskedEmail] = useState('');
  const [otp, setOtp] = useState('');
  const [resendTimer, setResendTimer] = useState(0);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (isAuthenticated && user) {
      navigate(homeForUser(user), { replace: true });
    }
  }, [isAuthenticated, user, navigate]);

  useEffect(() => {
    const msalError = sessionStorage.getItem('msal_login_error');
    if (msalError) {
      setError(msalError);
      sessionStorage.removeItem('msal_login_error');
    }
  }, []);

  // Countdown timer for OTP resend
  useEffect(() => {
    if (resendTimer <= 0) return;
    const id = setTimeout(() => setResendTimer(t => t - 1), 1000);
    return () => clearTimeout(id);
  }, [resendTimer]);

  async function handleGoogleSuccess(credentialResponse) {
    setError('');
    setLoading(true);
    try {
      const { token, user: u } = await loginWithGoogle(credentialResponse.credential, { portal: loginPortal });
      const msg = portalMismatchMessage(loginPortal, u);
      if (msg) {
        setError(msg);
        return;
      }
      login(token, u);
      navigate(homeForUser(u), { replace: true });
    } catch (err) {
      setError(err.message || 'Google login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  }

  async function handleMicrosoftLogin() {
    setError('');
    setLoading(true);
    try {
      await msalInstance.loginRedirect({
        scopes: ['openid', 'profile', 'email', 'User.Read'],
        prompt: 'select_account',
      });
    } catch (err) {
      setError(err.message || 'Microsoft login failed. Please try again.');
      setLoading(false);
    }
  }

  async function handlePasswordLogin(e) {
    e.preventDefault();
    setError('');
    if (loginPortal === 'client') {
      if (!clientIdentifier.trim()) {
        setError('Please enter your registered email or mobile.');
        return;
      }
    } else {
      if (!isValidEmail(email)) {
        setError('Please enter a valid email address.');
        return;
      }
      if (!password) {
        setError('Please enter your password.');
        return;
      }
    }
    setLoading(true);
    try {
      const result = await loginWithPassword(email, password, {
        portal: loginPortal,
        identifier: loginPortal === 'client' ? clientIdentifier.trim() : email,
      });
      if (result.otpRequired) {
        setMaskedEmail(result.maskedEmail || email);
        setOtpStep(true);
        setResendTimer(60);
      } else {
        const msg = portalMismatchMessage(loginPortal, result.user);
        if (msg) {
          setError(msg);
          return;
        }
        login(result.token, result.user);
        navigate(homeForUser(result.user), { replace: true });
      }
    } catch (err) {
      setError(err.message || 'Login failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  }

  async function handleVerifyOtp(e) {
    e.preventDefault();
    setError('');
    if (!otp || otp.length !== 6) {
      setError('Please enter the 6-digit OTP.');
      return;
    }
    setLoading(true);
    try {
      const { token, user: u } = await verifyEmailOtp(email, otp, {
        portal: loginPortal,
        identifier: loginPortal === 'client' ? clientIdentifier.trim() : email,
      });
      const msg = portalMismatchMessage(loginPortal, u);
      if (msg) {
        setError(msg);
        return;
      }
      login(token, u);
      navigate(homeForUser(u), { replace: true });
    } catch (err) {
      setError(err.message || 'Invalid OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  }

  const handleResendOtp = useCallback(async () => {
    if (resendTimer > 0) return;
    setError('');
    setResendTimer(60);
    try {
      await requestEmailOtp(email, {
        portal: loginPortal,
        identifier: loginPortal === 'client' ? clientIdentifier.trim() : email,
      });
    } catch (err) {
      setError(err.message || 'Failed to resend OTP. Please try again.');
    }
  }, [email, resendTimer, clientIdentifier, loginPortal]);

  function handleChangeEmail() {
    setOtpStep(false);
    setOtp('');
    setError('');
    setResendTimer(0);
  }

  return (
    <GoogleOAuthProvider clientId={GOOGLE_CLIENT_ID || 'dev-placeholder'}>
      <div style={s.page}>
        <div style={s.card}>
          <div style={s.logoWrap}>
            <img src={logoUrl} alt="CA Office Portal" style={s.logo} />
          </div>
          {portalLocked ? (
            (() => {
              const meta = PORTAL_META[loginPortal] || PORTAL_META.staff;
              const Icon = meta.Icon;
              return (
                <div style={{ marginBottom: 16 }}>
                  <div
                    role="status"
                    aria-label={`Signing in to ${meta.label} portal`}
                    style={{
                      width: '100%',
                      padding: '14px 16px',
                      borderRadius: 12,
                      border: `2px solid ${meta.accent}`,
                      background: meta.tint,
                      display: 'flex',
                      alignItems: 'center',
                      gap: 12,
                    }}
                  >
                    <span
                      style={{
                        width: 40,
                        height: 40,
                        borderRadius: 10,
                        background: '#fff',
                        color: meta.accent,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        flexShrink: 0,
                        boxShadow: '0 1px 2px rgba(15,23,42,0.06)',
                      }}
                    >
                      <Icon size={20} />
                    </span>
                    <div style={{ minWidth: 0 }}>
                      <div
                        style={{
                          fontSize: 11,
                          fontWeight: 700,
                          letterSpacing: '.06em',
                          color: meta.accent,
                          textTransform: 'uppercase',
                        }}
                      >
                        Signing in to
                      </div>
                      <div style={{ fontSize: 16, fontWeight: 800, color: '#0f172a' }}>
                        {meta.label} Portal
                      </div>
                      <div style={{ fontSize: 12, color: '#64748b', marginTop: 2 }}>
                        {meta.sub}
                      </div>
                    </div>
                  </div>
                  <div style={s.wrongPortalRow}>
                    Wrong portal?{' '}
                    <a href={MARKETING_URL} style={s.wrongPortalLink}>
                      Choose another at carahulgupta.in
                    </a>
                  </div>
                </div>
              );
            })()
          ) : (
            <div style={{ display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap' }}>
              <button
                type="button"
                onClick={() => setLoginPortal('client')}
                style={{
                  flex: 1,
                  minWidth: 80,
                  padding: '10px 12px',
                  borderRadius: 10,
                  border: loginPortal === 'client' ? '2px solid #15803d' : '1px solid #e2e8f0',
                  background: loginPortal === 'client' ? '#f0fdf4' : '#fff',
                  fontWeight: 700,
                  fontSize: 13,
                  cursor: 'pointer',
                  color: '#0f172a',
                }}
              >
                My CA
              </button>
              <button
                type="button"
                onClick={() => setLoginPortal('associate')}
                style={{
                  flex: 1,
                  minWidth: 80,
                  padding: '10px 12px',
                  borderRadius: 10,
                  border: loginPortal === 'associate' ? '2px solid #7c3aed' : '1px solid #e2e8f0',
                  background: loginPortal === 'associate' ? '#f5f3ff' : '#fff',
                  fontWeight: 700,
                  fontSize: 13,
                  cursor: 'pointer',
                  color: '#0f172a',
                }}
              >
                Associate
              </button>
              <button
                type="button"
                onClick={() => setLoginPortal('partner')}
                style={{
                  flex: 1,
                  minWidth: 80,
                  padding: '10px 12px',
                  borderRadius: 10,
                  border: loginPortal === 'partner' ? '2px solid #ea580c' : '1px solid #e2e8f0',
                  background: loginPortal === 'partner' ? '#fff7ed' : '#fff',
                  fontWeight: 700,
                  fontSize: 13,
                  cursor: 'pointer',
                  color: '#0f172a',
                }}
              >
                Partner
              </button>
              <button
                type="button"
                onClick={() => setLoginPortal('staff')}
                style={{
                  flex: 1,
                  minWidth: 80,
                  padding: '10px 12px',
                  borderRadius: 10,
                  border: loginPortal === 'staff' ? '2px solid #2563eb' : '1px solid #e2e8f0',
                  background: loginPortal === 'staff' ? '#eff6ff' : '#fff',
                  fontWeight: 700,
                  fontSize: 13,
                  cursor: 'pointer',
                  color: '#0f172a',
                }}
              >
                Core
              </button>
            </div>
          )}
          <h1 style={s.heading}>Sign in to your account</h1>
          <p style={s.subheading}>CA Rahul Gupta – Office Portal</p>

          {otpStep ? (
            /* ── OTP Verification Step ─────────────────────────────────── */
            <>
              <div style={s.otpInfo}>
                <strong>Check your inbox</strong><br />
                We sent a 6-digit OTP to <strong>{maskedEmail}</strong>.
                It expires in 10 minutes.{' '}
                <button style={s.changeLink} onClick={handleChangeEmail}>Change email</button>
              </div>
              <form onSubmit={handleVerifyOtp} style={{ ...s.form, marginTop: 16 }} noValidate>
                <label style={s.label} htmlFor="login-otp">Enter OTP</label>
                <input
                  id="login-otp"
                  type="text"
                  inputMode="numeric"
                  maxLength={6}
                  value={otp}
                  onChange={e => { setOtp(e.target.value.replace(/\D/g, '')); setError(''); }}
                  placeholder="_ _ _ _ _ _"
                  style={{ ...s.input, letterSpacing: 8, textAlign: 'center', fontSize: 22, fontWeight: 700 }}
                  autoComplete="one-time-code"
                  disabled={loading}
                  autoFocus
                />
                <button
                  type="submit"
                  style={{ ...s.primaryBtn, opacity: loading ? 0.7 : 1 }}
                  disabled={loading}
                >
                  {loading ? 'Verifying…' : 'Verify OTP & Sign In'}
                </button>
              </form>
              <div style={s.resendRow}>
                {resendTimer > 0 ? (
                  <span style={s.resendTimer}>Resend OTP in {resendTimer}s</span>
                ) : (
                  <button style={s.resendBtn} onClick={handleResendOtp} disabled={loading}>
                    Resend OTP
                  </button>
                )}
              </div>
            </>
          ) : (
            /* ── Email + Password Step ─────────────────────────────────── */
            <>
              {/* SSO — shown for all portals including client */}
              <div style={s.socialSection}>
                {GOOGLE_CLIENT_ID ? (
                  <div style={s.googleWrap}>
                    <GoogleLogin
                      onSuccess={handleGoogleSuccess}
                      onError={() => setError('Google login failed. Please try again.')}
                      width="340"
                      text="continue_with"
                      shape="rectangular"
                      size="large"
                      theme="outline"
                    />
                  </div>
                ) : (
                  <button
                    style={{ ...s.socialBtn, opacity: loading ? 0.7 : 1 }}
                    onClick={handleGoogleSuccess.bind(null, { credential: MOCK_GOOGLE_CREDENTIAL })}
                    disabled={loading}
                  >
                    <GoogleIcon /> Continue with Google
                  </button>
                )}
                {loginPortal !== 'client' && (
                  <button
                    style={{ ...s.socialBtn, opacity: loading ? 0.7 : 1 }}
                    onClick={handleMicrosoftLogin}
                    disabled={loading}
                  >
                    <MicrosoftIcon /> {loading ? 'Redirecting…' : 'Continue with Outlook'}
                  </button>
                )}
                {loginPortal === 'client' && (
                  <button
                    style={{ ...s.socialBtn, opacity: 0.5 }}
                    disabled
                    title="Apple Sign-In — coming soon"
                  >
                    <AppleIcon /> Continue with Apple
                  </button>
                )}
              </div>
              <div style={s.divider}>
                <div style={s.dividerLine} />
                <span style={s.dividerText}>or</span>
                <div style={s.dividerLine} />
              </div>
              <form onSubmit={handlePasswordLogin} style={s.form} noValidate>
                {loginPortal === 'client' ? (
                  <>
                    <label style={s.label} htmlFor="login-client-identifier">Registered email or mobile</label>
                    <input
                      id="login-client-identifier"
                      type="text"
                      value={clientIdentifier}
                      onChange={e => { setClientIdentifier(e.target.value); setError(''); }}
                      placeholder="name@example.com or 98XXXXXXXX"
                      style={s.input}
                      autoComplete="username"
                      disabled={loading}
                    />
                  </>
                ) : (
                  <>
                    <label style={s.label} htmlFor="login-email">Official email address</label>
                    <input
                      id="login-email"
                      type="email"
                      value={email}
                      onChange={e => { setEmail(e.target.value); setError(''); }}
                      placeholder="name@company.com"
                      style={s.input}
                      autoComplete="email"
                      disabled={loading}
                    />
                    <label style={s.label} htmlFor="login-password">Password</label>
                    <input
                      id="login-password"
                      type="password"
                      value={password}
                      onChange={e => { setPassword(e.target.value); setError(''); }}
                      placeholder="Enter your password"
                      style={s.input}
                      autoComplete="current-password"
                      disabled={loading}
                    />
                  </>
                )}
                <button
                  type="submit"
                  style={{ ...s.primaryBtn, opacity: loading ? 0.7 : 1 }}
                  disabled={loading}
                >
                  {loading ? 'Sending OTP…' : (loginPortal === 'client' ? 'Continue with OTP' : 'Sign In')}
                </button>
              </form>
            </>
          )}

          {error && (
            <div role="alert" aria-live="assertive" style={s.errorBox}>
              <strong>Error:</strong> {error}
            </div>
          )}
          <p style={s.adminNote}>
            Access is provided by admin. Contact support if you need access.
          </p>
        </div>
      </div>
    </GoogleOAuthProvider>
  );
}

function GoogleIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 48 48" style={{ flexShrink: 0 }}>
      <path fill="#4285F4" d="M44.5 20H24v8.5h11.8C34.7 33.9 29.9 37 24 37c-7.2 0-13-5.8-13-13s5.8-13 13-13c3.1 0 5.9 1.1 8.1 2.9l6.4-6.4C34.6 5.1 29.6 3 24 3 12.4 3 3 12.4 3 24s9.4 21 21 21c10.5 0 19.5-7.1 21-17H24v-8h20.5z" />
      <path fill="#34A853" d="M6.3 14.7l7 5.1C15.1 16.1 19.2 13 24 13c3.1 0 5.9 1.1 8.1 2.9l6.4-6.4C34.6 5.1 29.6 3 24 3c-7.7 0-14.3 4.4-17.7 11.7z" />
      <path fill="#FBBC05" d="M24 45c5.8 0 10.7-1.9 14.3-5.2l-6.6-5.4C29.9 36.1 27.1 37 24 37c-5.8 0-10.7-3.8-12.5-9.1l-7 5.4C8 40.1 15.4 45 24 45z" />
      <path fill="#EA4335" d="M44.5 20H24v8.5h11.8c-.9 2.8-2.8 5.1-5.3 6.6l6.6 5.4C41.3 37.1 44.5 31 44.5 24c0-1.3-.2-2.7-.5-4z" />
    </svg>
  );
}

function MicrosoftIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 21 21" style={{ flexShrink: 0 }}>
      <rect x="1" y="1" width="9" height="9" fill="#F25022" />
      <rect x="11" y="1" width="9" height="9" fill="#7FBA00" />
      <rect x="1" y="11" width="9" height="9" fill="#00A4EF" />
      <rect x="11" y="11" width="9" height="9" fill="#FFB900" />
    </svg>
  );
}

function AppleIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 814 1000" style={{ flexShrink: 0 }}>
      <path fill="#000" d="M788.1 340.9c-5.8 4.5-108.2 62.2-108.2 190.5 0 148.4 130.3 200.9 134.2 202.2-.6 3.2-20.7 71.9-68.7 141.9-42.8 61.6-87.5 123.1-155.5 123.1s-85.5-39.5-164-39.5c-76.5 0-103.7 40.8-165.9 40.8s-105.6-57.8-155.5-127.4C46 407.5 16.5 300.8 16.5 199.5c0-183.1 119.1-280.1 238.9-280.1 75.6 0 138.3 49.3 185.8 49.3 45.5 0 116.5-54.8 201.5-54.8zm-86.4-190.9c-31.3 33.3-58.9 80.8-58.9 128.3s2.6 7.4 5.2 10.6c29.1 3.2 70.7-21.8 93.5-50.4 21.8-27.1 37.1-70.7 37.1-110.1 0-5.2-.5-10.4-2.9-14.5-2.5-.6-5.2-.6-7.8-.6-26.4 0-58.9 14.5-66.2 36.7z"/>
    </svg>
  );
}

const s = {
  page: {
    minHeight: '100vh',
    background: '#F6F7FB',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '24px 16px',
    fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Inter, sans-serif",
  },
  card: {
    background: '#fff',
    borderRadius: 16,
    boxShadow: '0 4px 24px rgba(0,0,0,0.08)',
    border: '1px solid #E6E8F0',
    padding: '40px 36px 32px',
    width: '100%',
    maxWidth: 400,
  },
  logoWrap: { display: 'flex', justifyContent: 'center', marginBottom: 24 },
  logo: { maxWidth: 200, height: 'auto', objectFit: 'contain' },
  heading: { fontSize: 22, fontWeight: 700, color: '#0B1F3B', margin: '0 0 4px', textAlign: 'center' },
  subheading: { fontSize: 13, color: '#64748b', textAlign: 'center', margin: '0 0 28px' },
  socialSection: { display: 'flex', flexDirection: 'column', gap: 10 },
  googleWrap: { display: 'flex', justifyContent: 'center' },
  socialBtn: {
    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10,
    width: '100%', padding: '10px 16px', border: '1px solid #E6E8F0', borderRadius: 8,
    background: '#fff', fontSize: 14, fontWeight: 500, color: '#334155',
    cursor: 'pointer', transition: 'background 0.15s',
  },
  divider: { display: 'flex', alignItems: 'center', margin: '22px 0', gap: 10 },
  dividerLine: { flex: 1, height: 1, background: '#E6E8F0' },
  dividerText: { fontSize: 12, color: '#94a3b8', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.05em' },
  form: { display: 'flex', flexDirection: 'column', gap: 12 },
  label: { fontSize: 13, fontWeight: 600, color: '#334155' },
  input: {
    padding: '10px 12px', border: '1px solid #E6E8F0', borderRadius: 8,
    fontSize: 14, color: '#1e293b', background: '#F6F7FB', outline: 'none',
    width: '100%', boxSizing: 'border-box', fontFamily: 'inherit',
  },
  primaryBtn: {
    padding: '11px 0', background: '#F37920', color: '#fff', border: 'none',
    borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: 'pointer',
    width: '100%', transition: 'opacity 0.15s', letterSpacing: '0.01em',
  },
  otpInfo: { fontSize: 13, color: '#64748b', background: '#F6F7FB', borderRadius: 8, padding: '8px 12px', lineHeight: 1.5 },
  changeLink: { background: 'none', border: 'none', color: '#F37920', fontWeight: 600, fontSize: 13, cursor: 'pointer', padding: 0, textDecoration: 'underline' },
  resendRow: { display: 'flex', justifyContent: 'center', marginTop: 4 },
  resendTimer: { fontSize: 12, color: '#94a3b8' },
  resendBtn: { background: 'none', border: 'none', color: '#F37920', fontSize: 13, fontWeight: 600, cursor: 'pointer', padding: 0, textDecoration: 'underline' },
  errorBox: {
    marginTop: 12, background: '#FEF2F2', border: '1px solid #fecaca',
    borderRadius: 8, padding: '10px 14px', fontSize: 13, color: '#b91c1c', lineHeight: 1.5,
  },
  adminNote: { marginTop: 20, textAlign: 'center', fontSize: 12, color: '#94a3b8', lineHeight: 1.5 },
  wrongPortalRow: {
    marginTop: 8, fontSize: 12, color: '#94a3b8', textAlign: 'center', lineHeight: 1.5,
  },
  wrongPortalLink: {
    color: '#F37920', textDecoration: 'none', fontWeight: 600,
  },
};

