    if (portalTypes.some(p => p.name === val)) { setPortalError('This portal already exists.'); return; }
    try {
      const item = await createPortalType({ name: val, url: newPortalUrl.trim() });
      setPortalTypes(prev => [...prev, item]);
      setNewPortal('');
      setNewPortalUrl('');
      setPortalError('');
