import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../../auth/AuthContext';
import { API_BASE_URL, SUPER_ADMIN_EMAIL } from '../../../constants/config';
import { ROLE_LABELS, ROLE_BADGE_COLORS } from '../../../constants/roles';
import DestructiveConfirmModal from '../../../components/common/DestructiveConfirmModal';

/* ─── API helpers ─────────────────────────────────────────────────────────── */

async function apiFetch(token, path, options = {}) {
  const res = await fetch(`${API_BASE_URL}${path}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      Authorization:  `Bearer ${token}`,
      ...(options.headers || {}),
    },
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(json.message || `Error ${res.status}`);
  return json;
}

/* ─── Sub-components ──────────────────────────────────────────────────────── */

function RoleBadge({ role }) {
  const colors = ROLE_BADGE_COLORS[role] || ROLE_BADGE_COLORS.viewer;
  return (
    <span style={{
      display:       'inline-block',
      padding:       '2px 10px',
      borderRadius:  12,
      fontSize:      12,
      fontWeight:    600,
      background:    colors.bg,
      color:         colors.color,
      border:        `1px solid ${colors.border}`,
    }}>
      {ROLE_LABELS[role] || role}
    </span>
  );
}

function StatusBadge({ active }) {
  return (
    <span style={{
      display:      'inline-block',
      padding:      '2px 10px',
      borderRadius: 12,
      fontSize:     12,
      fontWeight:   600,
      background:   active ? '#dcfce7' : '#f3f4f6',
      color:        active ? '#166534' : '#6b7280',
      border:       `1px solid ${active ? '#86efac' : '#d1d5db'}`,
    }}>
      {active ? 'Active' : 'Inactive'}
    </span>
  );
}

/** Resolve role_id from API row (list rows historically omitted role_id). */
function resolveUserRoleId(user, roles) {
  if (!roles?.length) return '';
  if (user?.role_id != null && user.role_id !== '') return Number(user.role_id);
  const roleName = user?.role || user?.role_name;
  if (roleName) {
    const match = roles.find((r) => r.name === roleName);
    if (match) return match.id;
  }
  return roles[0]?.id ?? '';
}

/* ─── Add / Edit User Modal ──────────────────────────────────────────────── */

function UserModal({ mode, user, roles, onClose, onSave }) {
  const isPrimarySuperAdmin = mode === 'edit' && user?.email === SUPER_ADMIN_EMAIL;
  const [form, setForm] = useState({
    name:                   user?.name     || '',
    email:                  user?.email    || '',
    password:               '',
    role_id:                resolveUserRoleId(user, roles),
    is_active:              user?.is_active !== false,
    shift_target_minutes:   user?.shift_target_minutes ?? 510,
    shift_target_disabled:  user?.shift_target_disabled === true,
  });
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (mode !== 'edit' || !user) return;
    setForm((prev) => ({
      ...prev,
      role_id: resolveUserRoleId(user, roles),
    }));
  }, [mode, user, roles]);

  function set(field, value) {
    setForm(prev => ({ ...prev, [field]: value }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setError('');
    if (!form.shift_target_disabled) {
      const m = Number(form.shift_target_minutes);
      if (!Number.isFinite(m) || m < 60 || m > 1440) {
        setError('Daily target must be between 60 and 1440 minutes, or enable “does not apply”.');
        return;
      }
    }
    setSaving(true);
    try {
      await onSave(form);
      onClose();
    } catch (err) {
      setError(err.message || 'Save failed');
    } finally {
      setSaving(false);
    }
  }

  return (
    <div style={styles.overlay} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={styles.modal}>
        <div style={styles.modalHeader}>
          <h2 style={{ margin: 0, fontSize: 18, fontWeight: 700 }}>
            {mode === 'add' ? '➕ Add New User' : (isPrimarySuperAdmin ? '✏️ Shift target (primary account)' : '✏️ Edit User')}
          </h2>
          <button onClick={onClose} style={styles.closeBtn}>✕</button>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={styles.formBody}>
            {error && <div style={styles.errorBox}>{error}</div>}

            {isPrimarySuperAdmin && (
              <p style={{ margin: '0 0 8px', fontSize: 13, color: '#64748b', lineHeight: 1.45 }}>
                Name, email, role, and status are fixed for this account. You can change the daily shift target below.
              </p>
            )}

            <label style={styles.label}>Full Name *</label>
            <input
              style={styles.input}
              value={form.name}
              onChange={(e) => set('name', e.target.value)}
              required
              disabled={isPrimarySuperAdmin}
              placeholder="e.g. Priya Sharma"
            />

            <label style={styles.label}>Email Address *</label>
            <input
              style={styles.input}
              type="email"
              value={form.email}
              onChange={(e) => set('email', e.target.value)}
              required
              disabled={mode === 'edit' && user?.email === SUPER_ADMIN_EMAIL}
              placeholder="e.g. priya@example.com"
            />

            {mode === 'add' && (
              <>
                <label style={styles.label}>Password *</label>
                <input
                  style={styles.input}
                  type="password"
                  value={form.password}
                  onChange={(e) => set('password', e.target.value)}
                  required
                  minLength={8}
                  placeholder="Minimum 8 characters"
                />
              </>
            )}

            <label style={styles.label}>Role *</label>
            <select
              style={styles.input}
              value={form.role_id}
              onChange={(e) => set('role_id', Number(e.target.value))}
              disabled={isPrimarySuperAdmin}
            >
              {roles.map((r) => (
                <option key={r.id} value={r.id}>
                  {ROLE_LABELS[r.name] || r.display_name}
                </option>
              ))}
            </select>

            <label style={styles.label}>Daily target (minutes)</label>
            <input
              style={{
                ...styles.input,
                ...(form.shift_target_disabled ? { background: '#f8fafc', color: '#94a3b8' } : {}),
              }}
              type="number"
              min={form.shift_target_disabled ? undefined : 60}
              max={form.shift_target_disabled ? undefined : 1440}
              step={1}
              value={form.shift_target_minutes}
              disabled={form.shift_target_disabled}
              onChange={(e) => set('shift_target_minutes', Number(e.target.value))}
              placeholder="510"
            />
            <label style={{
              display: 'flex',
              alignItems: 'flex-start',
              gap: 10,
              marginTop: 10,
              cursor: 'pointer',
              fontSize: 13,
              fontWeight: 500,
              color: '#475569',
              lineHeight: 1.35,
            }}
            >
              <input
                type="checkbox"
                checked={form.shift_target_disabled}
                onChange={(e) => set('shift_target_disabled', e.target.checked)}
                style={{ marginTop: 2, accentColor: '#4f46e5', flexShrink: 0 }}
              />
              <span>Daily shift target does not apply (omit from targets in reports; no minimum-intimation for this user).</span>
            </label>

            {mode === 'edit' && (
              <>
                <label style={styles.label}>Status</label>
                <select
                  style={styles.input}
                  value={form.is_active ? 'active' : 'inactive'}
                  onChange={(e) => set('is_active', e.target.value === 'active')}
                  disabled={isPrimarySuperAdmin}
                >
                  <option value="active">Active</option>
                  <option value="inactive">Inactive</option>
                </select>
              </>
            )}
          </div>

          <div style={styles.modalFooter}>
            <button type="button" onClick={onClose} style={styles.cancelBtn}>
              Cancel
            </button>
            <button type="submit" disabled={saving} style={styles.saveBtn}>
              {saving ? 'Saving…' : 'Save User'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

/* ─── Main Page ───────────────────────────────────────────────────────────── */

export default function UserManagement() {
  const { session } = useAuth();
  const token = session?.token;

  const [users,      setUsers]      = useState([]);
  const [roles,      setRoles]      = useState([]);
  const [total,      setTotal]      = useState(0);
  const [page,       setPage]       = useState(1);
  const [perPage]                   = useState(20);
  const [search,     setSearch]     = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [loading,    setLoading]    = useState(true);
  const [error,      setError]      = useState('');
  const [modal,      setModal]      = useState(null); // null | { mode: 'add'|'edit', user? }
  const [deactivateTarget, setDeactivateTarget] = useState(null);
  const [deactivateBusy, setDeactivateBusy] = useState(false);
  const [deactivateErr, setDeactivateErr] = useState('');

  // ── Fetch data ─────────────────────────────────────────────────────────────

  const loadRoles = useCallback(async () => {
    if (!token || !API_BASE_URL) return;
    try {
      const res = await apiFetch(token, '/admin/roles');
      setRoles(res.data || []);
    } catch {
      // roles load failure is non-fatal
    }
  }, [token]);

  const loadUsers = useCallback(async () => {
    if (!token || !API_BASE_URL) {
      // Show demo data in mock mode
      setUsers([{
        id: 1, name: 'Rahul Gupta', email: SUPER_ADMIN_EMAIL,
        role: 'super_admin', is_active: true, last_login_at: null, login_provider: 'local',
        shift_target_minutes: 510, shift_target_disabled: false,
      }]);
      setTotal(1);
      setLoading(false);
      return;
    }
    setLoading(true);
    setError('');
    try {
      const params = new URLSearchParams({
        page:     String(page),
        per_page: String(perPage),
        ...(search     ? { search }      : {}),
        ...(roleFilter ? { role: roleFilter } : {}),
        ...(statusFilter ? { status: statusFilter } : {}),
      });
      const res = await apiFetch(token, `/admin/users?${params}`);
      setUsers(res.data || []);
      setTotal(res.pagination?.total || 0);
    } catch (err) {
      setError(err.message || 'Failed to load users');
    } finally {
      setLoading(false);
    }
  }, [token, page, perPage, search, roleFilter, statusFilter]);

  useEffect(() => { loadRoles(); }, [loadRoles]);
  useEffect(() => { loadUsers(); }, [loadUsers]);

  // ── Actions ────────────────────────────────────────────────────────────────

  async function handleSave(form) {
    if (!token || !API_BASE_URL) return;
    if (modal.mode === 'add') {
      await apiFetch(token, '/admin/users', {
        method: 'POST',
        body:   JSON.stringify(form),
      });
    } else {
      const { password: _pw, ...updateData } = form;
      const isPrimary = modal.user?.email === SUPER_ADMIN_EMAIL;
      const payload = isPrimary
        ? {
            shift_target_minutes:   updateData.shift_target_minutes,
            shift_target_disabled:  updateData.shift_target_disabled,
          }
        : updateData;
      await apiFetch(token, `/admin/users/${modal.user.id}`, {
        method: 'PUT',
        body:   JSON.stringify(payload),
      });
    }
    loadUsers();
  }

  async function executeDeactivateUser() {
    if (!token || !API_BASE_URL || !deactivateTarget) return;
    setDeactivateBusy(true);
    setDeactivateErr('');
    try {
      await apiFetch(token, `/admin/users/${deactivateTarget.id}`, { method: 'DELETE' });
      setDeactivateTarget(null);
      loadUsers();
    } catch (err) {
      setDeactivateErr(err.message || 'Failed to deactivate user');
    } finally {
      setDeactivateBusy(false);
    }
  }

  // ── Pagination ─────────────────────────────────────────────────────────────
  const lastPage = Math.max(1, Math.ceil(total / perPage));

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.pageHeader}>
        <div>
          <h1 style={styles.pageTitle}>👥 User Management</h1>
          <p style={styles.pageSubtitle}>{total} user{total !== 1 ? 's' : ''} total</p>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <a href="/admin/leaves" style={{ padding: '8px 16px', borderRadius: 8, border: '1px solid #E6E8F0', background: '#fff', color: '#475569', fontWeight: 600, fontSize: 13, cursor: 'pointer', textDecoration: 'none' }}>
            📅 Leaves
          </a>
          <button style={styles.addBtn} onClick={() => setModal({ mode: 'add' })}>
            + Add User
          </button>
        </div>
      </div>

      {/* Filters */}
      <div style={styles.filtersRow}>
        <input
          style={{ ...styles.filterInput, flex: 2 }}
          placeholder="🔍  Search by name or email…"
          value={search}
          onChange={(e) => { setSearch(e.target.value); setPage(1); }}
        />
        <select
          style={styles.filterInput}
          value={roleFilter}
          onChange={(e) => { setRoleFilter(e.target.value); setPage(1); }}
        >
          <option value="">All Roles</option>
          {Object.entries(ROLE_LABELS).map(([key, label]) => (
            <option key={key} value={key}>{label}</option>
          ))}
        </select>
        <select
          style={styles.filterInput}
          value={statusFilter}
          onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
        >
          <option value="">All Status</option>
          <option value="active">Active</option>
          <option value="inactive">Inactive</option>
        </select>
      </div>

      {/* Error */}
      {error && <div style={styles.errorBox}>{error}</div>}

      {/* Table */}
      <div style={styles.tableWrap}>
        <table style={styles.table}>
          <thead>
            <tr style={styles.thead}>
              <th style={styles.th}>User</th>
              <th style={styles.th}>Role</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Last Login</th>
              <th style={styles.th}>Provider</th>
              <th style={styles.th}>Target minutes</th>
              <th style={{ ...styles.th, textAlign: 'right' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td colSpan={7} style={{ textAlign: 'center', padding: 40, color: '#6b7280' }}>
                  Loading…
                </td>
              </tr>
            ) : users.length === 0 ? (
              <tr>
                <td colSpan={7} style={{ textAlign: 'center', padding: 40, color: '#6b7280' }}>
                  No users found.
                </td>
              </tr>
            ) : users.map((u) => {
              const isSuperAdmin = u.email === SUPER_ADMIN_EMAIL;
              return (
                <tr key={u.id} style={styles.tr}>
                  <td style={styles.td}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                      <div style={styles.avatar}>
                        {(u.name || '?').charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <div style={{ fontWeight: 600, color: '#1e293b' }}>
                          {u.name}
                          {isSuperAdmin && (
                            <span title="Primary account — profile locked; shift target can be edited" style={{ marginLeft: 6 }}>🔒</span>
                          )}
                        </div>
                        <div style={{ fontSize: 12, color: '#64748b' }}>{u.email}</div>
                      </div>
                    </div>
                  </td>
                  <td style={styles.td}>
                    <RoleBadge role={u.role || u.role_name} />
                  </td>
                  <td style={styles.td}>
                    <StatusBadge active={u.is_active} />
                  </td>
                  <td style={styles.td}>
                    {u.last_login_at
                      ? new Date(u.last_login_at).toLocaleDateString('en-IN', {
                          day: '2-digit', month: 'short', year: 'numeric',
                        })
                      : <span style={{ color: '#9ca3af' }}>Never</span>
                    }
                  </td>
                  <td style={styles.td}>
                    <span style={{ textTransform: 'capitalize', fontSize: 12, color: '#475569' }}>
                      {u.login_provider || 'local'}
                    </span>
                  </td>
                  <td style={styles.td}>
                    {u.shift_target_disabled === true ? (
                      <span style={{ color: '#94a3b8', fontSize: 13 }} title="Daily shift target does not apply">
                        —
                      </span>
                    ) : (
                      <span style={{ fontSize: 13, color: '#374151', fontVariantNumeric: 'tabular-nums' }}>
                        {Number(u.shift_target_minutes) || 510}
                      </span>
                    )}
                  </td>
                  <td style={{ ...styles.td, textAlign: 'right' }}>
                    <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                      <button
                        style={styles.editBtn}
                        onClick={() => setModal({ mode: 'edit', user: u })}
                      >
                        Edit
                      </button>
                      {!isSuperAdmin && u.is_active && (
                        <button
                          style={styles.deactivateBtn}
                          onClick={() => { setDeactivateErr(''); setDeactivateTarget(u); }}
                        >
                          Deactivate
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {lastPage > 1 && (
        <div style={styles.pagination}>
          <button
            style={styles.pageBtn}
            disabled={page <= 1}
            onClick={() => setPage(p => Math.max(1, p - 1))}
          >
            ← Prev
          </button>
          <span style={{ color: '#475569', fontSize: 13 }}>
            Page {page} of {lastPage}
          </span>
          <button
            style={styles.pageBtn}
            disabled={page >= lastPage}
            onClick={() => setPage(p => Math.min(lastPage, p + 1))}
          >
            Next →
          </button>
        </div>
      )}

      {deactivateTarget && (
        <DestructiveConfirmModal
          open
          title="Deactivate user?"
          tone="warning"
          titleAccent="#c2410c"
          confirmLabel="Deactivate"
          busy={deactivateBusy}
          error={deactivateErr}
          onClose={() => !deactivateBusy && setDeactivateTarget(null)}
          onConfirm={executeDeactivateUser}
        >
          <p style={{ margin: 0 }}>
            Deactivate <strong>{deactivateTarget.name}</strong> ({deactivateTarget.email})?
            They will no longer be able to sign in until an admin reactivates the account.
          </p>
        </DestructiveConfirmModal>
      )}

      {/* Modal */}
      {modal && (
        <UserModal
          mode={modal.mode}
          user={modal.user}
          roles={roles}
          onClose={() => setModal(null)}
          onSave={handleSave}
        />
      )}
    </div>
  );
}

