﻿import { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../../auth/AuthContext';
import { getContactKycExceptions } from '../../../services/reportService';

const CRITERIA = [
  { key: 'pan',               label: 'PAN Card' },
  { key: 'aadhaar',           label: 'Aadhaar Card' },
  { key: 'din',               label: 'DIN' },
  { key: 'driving_license',   label: 'Driving License' },
  { key: 'voter_id',          label: 'Voter ID' },
  { key: 'passport',          label: 'Passport' },
  { key: 'bank_proof',        label: 'Bank Proof' },
  { key: 'utility_telephone', label: 'Utility Bill - Telephone' },
  { key: 'utility_water',     label: 'Utility Bill - Water & Sewage' },
  { key: 'utility_electricity', label: 'Utility Bill - Electricity' },
  { key: 'signature',         label: 'Signature' },
  { key: 'photograph',        label: 'Photograph' },
];

const STATUS_LABEL = {
  active: 'Active',
  inactive: 'Inactive',
  prospect: 'Prospect',
  lead: 'Lead',
};

export default function ContactKycExceptionsReport() {
  const { hasPermission } = useAuth();
  const canView = hasPermission('clients.view');

  const [selected, setSelected] = useState(() => new Set(['pan', 'aadhaar']));
  const [includeInactive, setIncludeInactive] = useState(false);
  const [page, setPage] = useState(1);
  const perPage = 25;
  const [rows, setRows] = useState([]);
  const [pagination, setPagination] = useState({ total: 0, last_page: 1 });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const load = useCallback(() => {
    if (!canView) return;
    const keys = [...selected];
    if (keys.length === 0) {
      setRows([]);
      setPagination({ total: 0, last_page: 1 });
      setError('Select at least one criterion.');
      return;
    }
    setLoading(true);
    setError('');
    getContactKycExceptions({ missingKeys: keys, page, perPage, includeInactive })
      .then(({ rows: r, pagination: p }) => {
        setRows(r);
        setPagination({ total: p.total ?? 0, last_page: p.last_page ?? 1 });
      })
      .catch((e) => {
        setError(e.message || 'Failed to load report.');
        setRows([]);
      })
      .finally(() => setLoading(false));
  }, [canView, selected, page, perPage, includeInactive]);

  useEffect(() => {
    load();
  }, [load]);

  function toggleCriterion(key) {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
    setPage(1);
  }

  const criteriaLabel = Object.fromEntries(CRITERIA.map(({ key, label }) => [key, label]));
  const colSpan = 6;

  if (!canView) {
    return (
      <div style={{ padding: 24 }}>
        <p style={{ color: '#64748b' }}>You do not have permission to view this report.</p>
      </div>
    );
  }

  return (
    <div style={{ padding: 24, maxWidth: 1280 }}>
      <h1 style={{ fontSize: 22, fontWeight: 700, color: '#0B1F3B', marginBottom: 8 }}>
        Contact KYC exceptions
      </h1>
      <p style={{ fontSize: 13, color: '#64748b', marginBottom: 20, maxWidth: 720 }}>
        Lists contacts where <strong>any</strong> selected KYC document has not been uploaded, so
        staff can follow up and collect the missing documents.
      </p>

      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 16, alignItems: 'flex-end', marginBottom: 20 }}>
        <fieldset style={{ border: 'none', margin: 0, padding: 0 }}>
          <legend style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 8 }}>
            Missing KYC document (any of)
          </legend>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12 }}>
            {CRITERIA.map(({ key, label }) => (
              <label
                key={key}
                style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 13, color: '#334155', cursor: 'pointer' }}
              >
                <input
                  type="checkbox"
                  checked={selected.has(key)}
                  onChange={() => toggleCriterion(key)}
                />
                {label}
              </label>
            ))}
          </div>
        </fieldset>
        <label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 13, color: '#334155', cursor: 'pointer' }}>
          <input
            type="checkbox"
            checked={includeInactive}
            onChange={(e) => { setIncludeInactive(e.target.checked); setPage(1); }}
          />
          Include inactive
        </label>
      </div>

      {error && <div style={{ color: '#dc2626', fontSize: 13, marginBottom: 12 }}>{error}</div>}

      <div style={{ background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0', overflow: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
          <thead>
            <tr style={{ background: '#f8fafc', textAlign: 'left' }}>
              {['Contact', 'Group', 'Email', 'Status', 'Missing KYC Documents', 'View'].map((h) => (
                <th
                  key={h}
                  style={{ padding: '10px 12px', color: '#64748b', fontWeight: 600, fontSize: 12, borderBottom: '2px solid #e2e8f0' }}
                >
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td colSpan={colSpan} style={{ padding: 24, textAlign: 'center', color: '#94a3b8' }}>Loading…</td>
              </tr>
            ) : rows.length === 0 ? (
              <tr>
                <td colSpan={colSpan} style={{ padding: 24, textAlign: 'center', color: '#94a3b8' }}>
                  No contacts with missing KYC documents.
                </td>
              </tr>
            ) : (
              rows.map((r) => (
                <tr key={r.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                  <td style={{ padding: '10px 12px', fontWeight: 600 }}>
                    <Link to={`/clients/contacts/${r.id}/edit`} style={{ color: '#0B1F3B', textDecoration: 'none' }}>
                      {r.displayName}
                    </Link>
                  </td>
                  <td style={{ padding: '10px 12px', color: '#64748b' }}>{r.groupName || '—'}</td>
                  <td style={{ padding: '10px 12px' }}>{r.email || '—'}</td>
                  <td style={{ padding: '10px 12px', color: '#64748b' }}>
                    {STATUS_LABEL[r.contactStatus] || r.contactStatus || '—'}
                  </td>
                  <td style={{ padding: '10px 12px' }}>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                      {(r.missingCategories || []).map((cat) => (
                        <span
                          key={cat}
                          style={{
                            fontSize: 11,
                            fontWeight: 600,
                            padding: '2px 8px',
                            borderRadius: 6,
                            background: '#fef3c7',
                            color: '#92400e',
                          }}
                        >
                          {criteriaLabel[cat] || cat}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td style={{ padding: '10px 12px' }}>
                    <Link
                      to={`/clients/contacts/${r.id}/edit`}
                      style={{ fontSize: 12, fontWeight: 600, color: 'var(--portal-primary)' }}
                    >
                      Edit
                    </Link>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {pagination.last_page > 1 && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginTop: 16, fontSize: 13, color: '#64748b' }}>
          <button
            type="button"
            disabled={page <= 1}
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            style={{
              padding: '6px 12px',
              borderRadius: 8,
              border: '1px solid #e2e8f0',
              background: page <= 1 ? '#f8fafc' : '#fff',
              cursor: page <= 1 ? 'not-allowed' : 'pointer',
            }}
          >
            Previous
          </button>
          <span>
            Page {page} of {pagination.last_page} ({pagination.total} total)
          </span>
          <button
            type="button"
            disabled={page >= pagination.last_page}
            onClick={() => setPage((p) => p + 1)}
            style={{
              padding: '6px 12px',
              borderRadius: 8,
              border: '1px solid #e2e8f0',
              background: page >= pagination.last_page ? '#f8fafc' : '#fff',
              cursor: page >= pagination.last_page ? 'not-allowed' : 'pointer',
            }}
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { ShieldCheck, AlertCircle, Mail, Smartphone, RefreshCw, Download, Filter } from 'lucide-react';
import { API_BASE_URL } from '../../../constants/config';
import VerificationBadge from '../../../components/verification/VerificationBadge';

function authHeaders() {
  const token = localStorage.getItem('auth_token');
  return { 'Content-Type': 'application/json', ...(token ? { Authorization: `Bearer ${token}` } : {}) };
}

export default function ContactVerificationExceptions() {
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [typeFilter, setTypeFilter] = useState('both');

  useEffect(() => {
    load();
  }, [typeFilter]);

  async function load() {
    setLoading(true);
    setError('');
    try {
      const res = await fetch(`${API_BASE_URL}/admin/contacts/verification/exceptions?type=${typeFilter}&limit=200`, { headers: authHeaders() });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Failed to load');
      setItems(data.data?.items || []);
      setTotal(data.data?.total || 0);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }

  const unverifiedEmail = items.filter((c) => !c.email_verified && c.email);
  const unverifiedMobile = items.filter((c) => !c.mobile_verified && c.mobile);

  return (
    <div style={{ padding: 24, maxWidth: 1100, margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <div>
          <h1 style={{ fontSize: 22, fontWeight: 700, color: '#0f172a', margin: 0 }}>
            Verification Exceptions
          </h1>
          <p style={{ fontSize: 13, color: '#64748b', margin: '4px 0 0' }}>
            Clients with unverified email or mobile — {total} records
          </p>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} style={selectStyle}>
            <option value="both">Email & Mobile</option>
            <option value="email">Unverified Email only</option>
            <option value="mobile">Unverified Mobile only</option>
          </select>
          <button onClick={load} style={btnOutline}><RefreshCw size={13} /> Refresh</button>
        </div>
      </div>

      {/* Summary cards */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 14, marginBottom: 20 }}>
        {[
          { label: 'Total Exceptions', value: total, icon: AlertCircle, color: '#ef4444', bg: '#fef2f2' },
          { label: 'Unverified Email', value: unverifiedEmail.length, icon: Mail, color: '#d97706', bg: '#fffbeb' },
          { label: 'Unverified Mobile', value: unverifiedMobile.length, icon: Smartphone, color: '#7c3aed', bg: '#f5f3ff' },
        ].map((stat) => {
          const Icon = stat.icon;
          return (
            <div key={stat.label} style={{ background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0', padding: '16px 20px', display: 'flex', alignItems: 'center', gap: 14 }}>
              <div style={{ width: 40, height: 40, borderRadius: 10, background: stat.bg, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <Icon size={18} color={stat.color} />
              </div>
              <div>
                <div style={{ fontSize: 22, fontWeight: 700, color: '#1e293b' }}>{stat.value}</div>
                <div style={{ fontSize: 12, color: '#64748b' }}>{stat.label}</div>
              </div>
            </div>
          );
        })}
      </div>

      {error && (
        <div style={{ background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 8, padding: '12px 16px', marginBottom: 16, fontSize: 13, color: '#dc2626' }}>
          {error}
        </div>
      )}

      <div style={{ background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#f8fafc', borderBottom: '2px solid #e2e8f0' }}>
              {['Name', 'Email', 'Email Status', 'Mobile', 'Mobile Status', 'Added'].map((h) => (
                <th key={h} style={{ textAlign: 'left', padding: '10px 14px', fontSize: 11, fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.06em' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={6} style={{ textAlign: 'center', padding: '32px', color: '#94a3b8', fontSize: 13 }}>Loading…</td></tr>
            ) : items.length === 0 ? (
              <tr>
                <td colSpan={6} style={{ textAlign: 'center', padding: '40px' }}>
                  <ShieldCheck size={40} style={{ margin: '0 auto 12px', display: 'block', color: '#22c55e', opacity: 0.6 }} />
                  <div style={{ fontSize: 14, fontWeight: 600, color: '#1e293b', marginBottom: 4 }}>All contacts verified!</div>
                  <div style={{ fontSize: 13, color: '#64748b' }}>No unverified contacts found for the selected filter.</div>
                </td>
              </tr>
            ) : (
              items.map((c) => (
                <tr key={c.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                  <td style={{ padding: '12px 14px', fontSize: 13, fontWeight: 500, color: '#1e293b' }}>{c.name}</td>
                  <td style={{ padding: '12px 14px', fontSize: 12, color: '#64748b' }}>{c.email || '—'}</td>
                  <td style={{ padding: '12px 14px' }}>
                    {c.email ? (
                      <VerificationBadge
                        verified={c.email_verified}
                        field="email"
                        value={c.email}
                        clientId={c.id}
                        onVerified={load}
                      />
                    ) : <span style={{ fontSize: 11, color: '#94a3b8' }}>No email</span>}
                  </td>
                  <td style={{ padding: '12px 14px', fontSize: 12, color: '#64748b' }}>{c.mobile || '—'}</td>
                  <td style={{ padding: '12px 14px' }}>
                    {c.mobile ? (
                      <VerificationBadge
                        verified={c.mobile_verified}
                        field="mobile"
                        value={c.mobile}
                        clientId={c.id}
                        onVerified={load}
                      />
                    ) : <span style={{ fontSize: 11, color: '#94a3b8' }}>No mobile</span>}
                  </td>
                  <td style={{ padding: '12px 14px', fontSize: 12, color: '#94a3b8' }}>
                    {c.created_at ? new Date(c.created_at).toLocaleDateString('en-IN') : '—'}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const btnOutline = { display: 'inline-flex', alignItems: 'center', gap: 6, background: '#fff', color: '#334155', border: '1px solid #e2e8f0', borderRadius: 8, padding: '7px 14px', fontSize: 13, fontWeight: 500, cursor: 'pointer' };
const selectStyle = { padding: '7px 12px', border: '1px solid #e2e8f0', borderRadius: 8, fontSize: 13, color: '#1e293b', background: '#f8fafc', outline: 'none', cursor: 'pointer' };

