    firmBankAccountId: '',
    description: '',
    notes: '',
    ledgerMovementKind: 'fees',
  });
  const [banks, setBanks] = useState([]);
  const [banksLoading, setBanksLoading] = useState(false);
  const [err, setErr] = useState('');
