  useEffect(() => {
    if (!ledgerClientId || (tab !== 'ledger' && tab !== 'bill_settlement')) {
      setLedgerRecoveryStatus(null);
      return undefined;
    }
    const entityType = ledgerEntityType === 'organization' ? 'organization' : 'client';
    const entityId = parseInt(ledgerClientId, 10);
