            </div>
          )}
          {canDeleteInvoice && selectedPaymentIds.length > 0 && (
            <div style={{ padding: '10px 16px', background: '#fef2f2', borderBottom: '1px solid #fecaca', display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap' }}>
