                  <th style={{ ...thStyle, width: 36 }}>
                    <input
                      type="checkbox"
                      title="Select all"
                      checked={paymentExpenses.length > 0 && paymentExpenses.every((p) => selectedPaymentIds.some((x) => Number(x) === Number(p.id)))}
