                        if (e.target.checked) {
                          setSelectedRebateIds(rebates.map((x) => x.id));
                        } else {
                          setSelectedRebateIds([]);
                        }
                      }}
                    />
                  </th>
                )}
                {['Date','Client','Amount','Status','Narration','Billing Profile','Notes','Last updated by','Actions'].map(h=><th key={h} style={thStyle}>{h}</th>)}
