                      <table style={{ ...tableStyle, marginBottom: 0 }}>
                        <thead>
                          <tr>
                            {ledgerTableHeaders(cls === 'parked' && canEditInvoice && !isGroupLedgerScope).map(h=>(
                              <th key={h} style={thStyle}>{h}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {clsRows.map((e, i) => (
                            <tr
                              key={e.synthetic ? e.id : `${e.id ?? 'row'}-${i}`}
