                ) : (
                  <div style={{ ...s.cardImg, ...s.cardImgPlaceholder }}>
                    <span style={{ fontSize: 32, opacity: 0.4 }}>📄</span>
                  </div>
                )}
                <div style={s.cardBody}>
                  <div style={s.cardMeta}>
                    <span style={{ ...s.catBadge, ...CATEGORY_STYLES[post.category] }}>
                      {categoryLabel(post.category)}
                    </span>
                    <span style={s.cardDate}>{formatDate(post.published_at)}</span>
                  </div>
                  <h2 style={s.cardTitle}>{post.title}</h2>
                  {post.excerpt && (
                    <p style={s.cardExcerpt}>{post.excerpt}</p>
                  )}
                  <div style={s.cardFooter}>
                    <span style={s.cardAuthor}>{post.author_name || 'CA Rahul Gupta'}</span>
                    <span style={s.readMore}>Read more →</span>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}

        {/* ── CTA section ───────────────────────────────────────────────── */}
        <BlogCTA />

        {/* ── Footer ────────────────────────────────────────────────────── */}
        <footer style={s.footer}>
          <p style={{ margin: 0, color: '#94a3b8', fontSize: 13 }}>
            © {new Date().getFullYear()} CA Rahul Gupta Office &bull; All rights reserved
          </p>
        </footer>
      </div>

      <style>{`
        @keyframes blog-spin {
          from { transform: rotate(0deg); }
          to   { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

// ── Styles ───────────────────────────────────────────────────────────────────

const s = {
  page: {
    minHeight: '100vh',
    background: '#f8fafc',
    fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
  },

  // Nav
  nav: {
    background: '#fff',
    borderBottom: '1px solid #e2e8f0',
    position: 'sticky',
    top: 0,
    zIndex: 100,
  },
  navInner: {
    maxWidth: 1100,
    margin: '0 auto',
    padding: '0 24px',
    height: 58,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  },
  navLogo: {
    fontSize: 18,
    fontWeight: 800,
    color: '#0f172a',
    textDecoration: 'none',
    letterSpacing: '-0.02em',
  },
  navLogoAccent: {
    color: '#F37920',
  },
  navLinks: {
    display: 'flex',
    alignItems: 'center',
    gap: 20,
  },
  navLink: {
    fontSize: 14,
    fontWeight: 500,
    color: '#475569',
    textDecoration: 'none',
  },
  navLogin: {
    fontSize: 13,
    fontWeight: 600,
    color: '#F37920',
    textDecoration: 'none',
    padding: '6px 14px',
    border: '1px solid #F37920',
    borderRadius: 8,
  },

  // Hero
  hero: {
