};
const btnSecondary = {
  padding: '8px 14px', background: '#f1f5f9', color: '#334155',
  border: '1px solid #e2e8f0', borderRadius: 8, cursor: 'pointer', fontSize: 13,
};
const btnDanger = {
  padding: '8px 14px', background: '#dc2626', color: '#fff',
