import { useState, useEffect } from 'react';
import { useStaffUsers } from '../../../hooks/useStaffUsers';
import { updateRegister } from '../services/registerService';
import DateInput from '../../../components/common/DateInput';

/**
 * RegisterEntryModal
 *
 * Slide-in right panel for editing a register entry's filing details:
 *   filed_date, filed_by, acknowledgment_number, error_number, late_fee, notes, status
 *
 * Props:
 *   row        {Object|null}  The register row being edited (null = closed)
 *   onClose    {Function}     Called when user closes without saving
 *   onSaved    {Function}     Called with the updated row after save
 */
export default function RegisterEntryModal({ row, onClose, onSaved }) {
  const { staffUsers } = useStaffUsers();
  const [form, setForm]     = useState(null);
  const [saving, setSaving] = useState(false);
  const [error, setError]   = useState('');

  // Sync form state when the row prop changes
  useEffect(() => {
    if (!row) { setForm(null); return; }
    setError('');
    setForm({
      status:                 row.status                 ?? 'pending',
      filed_date:             row.filed_date             ?? '',
      filed_by:               row.filed_by               ?? '',
      acknowledgment_number:  row.acknowledgment_number  ?? '',
      error_number:           row.error_number           ?? '',
      late_fee:               row.late_fee != null ? String(row.late_fee) : '',
      notes:                  row.notes                  ?? '',
    });
  }, [row]);

  if (!row || !form) return null;

  function set(field, value) {
    setForm(prev => ({ ...prev, [field]: value }));
  }

  async function handleSave() {
    setSaving(true);
    setError('');
    try {
      const payload = {
        status:                form.status                || null,
        filed_date:            form.filed_date            || null,
        filed_by:              form.filed_by              ? Number(form.filed_by) : null,
        acknowledgment_number: form.acknowledgment_number || null,
        error_number:          form.error_number          || null,
        late_fee:              form.late_fee !== '' ? parseFloat(form.late_fee) : null,
        notes:                 form.notes                 || null,
      };
      const updated = await updateRegister(row.id, payload);
      onSaved(updated ?? { ...row, ...payload });
    } catch (e) {
      setError(e.message || 'Failed to save');
    } finally {
      setSaving(false);
    }
  }

  const clientName = row.client_name || '—';
  const returnType = row.return_type || row.engagement_type_name || '—';
  const period     = row.period_label || row.period || '—';

  return (
    <>
      {/* Backdrop */}
      <div
        onClick={onClose}
        style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.25)', zIndex: 999,
        }}
      />

      {/* Panel */}
      <div style={{
        position: 'fixed', top: 0, right: 0, height: '100vh', width: 420,
        background: '#fff', boxShadow: '-4px 0 20px rgba(0,0,0,.12)',
        zIndex: 1000, display: 'flex', flexDirection: 'column',
        fontFamily: 'inherit',
      }}>
        {/* Header */}
        <div style={{
          padding: '20px 24px', borderBottom: '1px solid #e2e8f0',
          display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between',
        }}>
          <div>
            <div style={{ fontSize: 15, fontWeight: 700, color: '#1e293b' }}>
              Update Register Entry
            </div>
            <div style={{ fontSize: 12, color: '#64748b', marginTop: 2 }}>
              {clientName} &mdash; {returnType} &mdash; {period}
            </div>
          </div>
          <button
            type="button"
            onClick={onClose}
            style={{
              background: 'none', border: 'none', cursor: 'pointer',
              fontSize: 20, color: '#94a3b8', lineHeight: 1, padding: '0 2px',
            }}
          >
            &times;
          </button>
        </div>

        {/* Body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 24px' }}>
          {/* Status */}
          <Field label="Status">
            <select
              value={form.status}
              onChange={e => set('status', e.target.value)}
              style={inputStyle}
            >
              <option value="pending">Pending</option>
              <option value="filed">Filed</option>
              <option value="na">N/A</option>
            </select>
          </Field>

          {/* Filed date */}
          <Field label="Date of Filing">
            <DateInput
              value={form.filed_date}
              onChange={e => set('filed_date', e.target.value)}
              style={inputStyle}
              placeholder="YYYY-MM-DD"
            />
          </Field>

          {/* Filed by */}
          <Field label="Filed by">
            <select
              value={form.filed_by}
              onChange={e => set('filed_by', e.target.value)}
              style={inputStyle}
            >
              <option value="">— Select staff —</option>
              {staffUsers.map(u => (
                <option key={u.id} value={u.id}>{u.name}</option>
              ))}
            </select>
          </Field>

          {/* Acknowledgment number */}
          <Field label="Acknowledgment / Reference No.">
            <input
              type="text"
              value={form.acknowledgment_number}
              onChange={e => set('acknowledgment_number', e.target.value)}
              style={inputStyle}
              placeholder="Enter ack / reference number"
            />
          </Field>

          {/* Error number */}
          <Field label="Error Number (if any)">
            <input
              type="text"
              value={form.error_number}
              onChange={e => set('error_number', e.target.value)}
              style={inputStyle}
              placeholder="Enter error number"
            />
          </Field>

          {/* Late fee */}
          <Field label="Late Fee (₹)">
            <input
              type="number"
              value={form.late_fee}
              onChange={e => set('late_fee', e.target.value)}
              style={inputStyle}
              placeholder="0"
              min="0"
              step="1"
            />
          </Field>

          {/* Notes */}
          <Field label="Notes">
            <textarea
              value={form.notes}
              onChange={e => set('notes', e.target.value)}
              rows={3}
              style={{ ...inputStyle, resize: 'vertical', minHeight: 72 }}
              placeholder="Optional internal notes"
            />
          </Field>

          {error && (
            <div style={{
              marginTop: 8, padding: '10px 12px',
              background: '#fef2f2', color: '#dc2626',
              borderRadius: 6, fontSize: 13,
            }}>
              {error}
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{
          padding: '16px 24px', borderTop: '1px solid #e2e8f0',
          display: 'flex', gap: 10, justifyContent: 'flex-end',
        }}>
          <button
            type="button"
            onClick={onClose}
            style={cancelBtnStyle}
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={handleSave}
            disabled={saving}
            style={saveBtnStyle(saving)}
          >
            {saving ? 'Saving…' : 'Save Changes'}
          </button>
        </div>
      </div>
    </>
  );
}

function Field({ label, children }) {
  return (
    <div style={{ marginBottom: 16 }}>
      <label style={{
        display: 'block', fontSize: 12, fontWeight: 600,
        color: '#475569', marginBottom: 6,
      }}>
        {label}
      </label>
      {children}
    </div>
  );
}

const inputStyle = {
  width: '100%', padding: '8px 10px',
  border: '1px solid #e2e8f0', borderRadius: 6,
  fontSize: 13, color: '#334155',
  background: '#fff', boxSizing: 'border-box',
};

const cancelBtnStyle = {
  padding: '8px 18px', background: '#f8fafc',
  border: '1px solid #e2e8f0', borderRadius: 7,
  fontSize: 13, fontWeight: 600, color: '#475569', cursor: 'pointer',
};

const saveBtnStyle = (disabled) => ({
  padding: '8px 22px',
  background: disabled ? '#93c5fd' : '#2563eb',
  border: 'none', borderRadius: 7,
  fontSize: 13, fontWeight: 600, color: '#fff',
  cursor: disabled ? 'wait' : 'pointer',
});

import { useState } from 'react';
import {
  Pin, PinOff, CheckCircle2, Bell, Trash2,
  Eye, Users, Lock, ChevronDown, ChevronUp,
} from 'lucide-react';
import { updateServiceLog, deleteServiceLog, sendLogReminder } from '../services/serviceLogService';
import DestructiveConfirmModal from '../../../components/common/DestructiveConfirmModal'; ───────────────────────────────────────────────────────────────
const TYPE_CONFIG = {
  note:             { label: 'Note',             bg: '#EFF6FF', color: '#1d4ed8', border: '#bfdbfe' },
  status_change:    { label: 'Status Change',    bg: '#F0FDF4', color: '#16a34a', border: '#bbf7d0' },
  follow_up:        { label: 'Follow-up',        bg: '#FFFBEB', color: '#d97706', border: '#fde68a' },
  document_request: { label: 'Document Request', bg: '#FDF4FF', color: '#7c3aed', border: '#e9d5ff' },
  internal_message: { label: 'Internal',         bg: '#F1F5F9', color: '#475569', border: '#cbd5e1' },
  reminder:         { label: 'Reminder',         bg: '#FFF7ED', color: '#ea580c', border: '#fed7aa' },
  system:           { label: 'System',           bg: '#F8FAFC', color: '#94a3b8', border: '#e2e8f0' },
};

const VISIBILITY_CONFIG = {
  internal:  { label: 'Internal',  Icon: Lock,  color: '#64748b' },
  associate: { label: 'Associate', Icon: Users, color: '#2563eb' },
  client:    { label: 'Client',    Icon: Eye,   color: '#16a34a' },
};

export default function ServiceLogEntry({
  entry,
  serviceId,
  isSuperAdmin,
  canEdit,
  onUpdated,
  onDeleted,
}) {
  const [expanded, setExpanded]   = useState(false);
  const [busy, setBusy]           = useState(false);
  const [actionErr, setActionErr] = useState('');
  const [confirmDeleteOpen, setConfirmDeleteOpen] = useState(false);

  const type       = entry.log_type    || 'note';
  const vis        = entry.visibility  || 'internal';
  const typeConf   = TYPE_CONFIG[type]    || TYPE_CONFIG.note;
  const visConf    = VISIBILITY_CONFIG[vis] || VISIBILITY_CONFIG.internal;
  const VisIcon    = visConf.Icon;

  const isResolved    = Boolean(entry.is_resolved);
  const isPinned      = Boolean(entry.is_pinned);
  const hasFollowUp   = Boolean(entry.follow_up_date);
  const canRemind     = hasFollowUp && !isResolved && (vis === 'client' || vis === 'associate');
  const isOverdue     = hasFollowUp && !isResolved && entry.follow_up_date < todayStr();
  const isDueToday    = hasFollowUp && !isResolved && entry.follow_up_date === todayStr();
  const messageShort  = entry.message?.length > 200 && !expanded;

  async function handle(fn) {
    setBusy(true);
    setActionErr('');
    try { await fn(); }
    catch (e) { setActionErr(e.message || 'Action failed.'); }
    finally { setBusy(false); }
  }

  async function togglePin() {
    handle(async () => {
      const updated = await updateServiceLog(serviceId, entry.id, { is_pinned: !isPinned });
      onUpdated(updated);
    });
  }

  async function resolve() {
    handle(async () => {
      const updated = await updateServiceLog(serviceId, entry.id, { resolve: true });
      onUpdated(updated);
    });
  }

  async function sendReminder() {
    handle(async () => {
      const updated = await sendLogReminder(serviceId, entry.id);
      onUpdated(updated);
    });
  }

  async function handleDeleteConfirmed() {
    setBusy(true);
    setActionErr('');
    try {
      await deleteServiceLog(serviceId, entry.id);
      setConfirmDeleteOpen(false);
      onDeleted(entry.id);
    } catch (e) {
      setActionErr(e.message || 'Delete failed.');
    } finally {
      setBusy(false);
    }
  }

  return (
    <>
    <div
      style={{
        ...entryWrap,
        ...(isPinned ? pinnedStyle : {}),
        ...(isResolved ? resolvedStyle : {}),
      }}
    >
      {/* Top row: type badge + visibility + timestamp */}
      <div style={entryTop}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, flex: 1, flexWrap: 'wrap' }}>
          {/* Type badge */}
          <span style={{
            ...typeBadge,
            background: typeConf.bg,
            color:       typeConf.color,
            border:      `1px solid ${typeConf.border}`,
          }}>
            {typeConf.label}
          </span>

          {/* Visibility badge */}
          <span style={{
            ...visBadge,
            color: visConf.color,
          }}>
            <VisIcon size={11} style={{ marginRight: 3 }} />
            {visConf.label}
          </span>

          {/* Pin indicator */}
          {isPinned && (
            <span style={{ fontSize: 11, color: 'var(--portal-primary)', display: 'flex', alignItems: 'center', gap: 3 }}>
              <Pin size={11} /> Pinned
            </span>
          )}

          {/* Follow-up date chip */}
          {hasFollowUp && (
            <span style={{
              ...followUpChip,
              background: isOverdue  ? '#FFF1F2' : isDueToday ? '#FFFBEB' : '#F0FDF4',
              color:      isOverdue  ? '#dc2626' : isDueToday ? '#d97706' : '#15803d',
              border:     `1px solid ${isOverdue ? '#fecdd3' : isDueToday ? '#fde68a' : '#bbf7d0'}`,
            }}>
              {isOverdue  ? '⚠ Overdue: ' : isDueToday ? '⏰ Due today: ' : '📅 Follow-up: '}
              {entry.follow_up_date}
            </span>
          )}

          {/* Resolved badge */}
          {isResolved && (
            <span style={resolvedBadge}>
              <CheckCircle2 size={11} style={{ marginRight: 3 }} /> Resolved
            </span>
          )}
        </div>

        {/* Timestamp + author */}
        <div style={{ fontSize: 11, color: '#94a3b8', flexShrink: 0, textAlign: 'right' }}>
          <div>{formatDateTime(entry.created_at)}</div>
          {entry.created_by_name && (
            <div style={{ marginTop: 1 }}>{entry.created_by_name}</div>
          )}
        </div>
      </div>

      {/* Message body */}
      <div style={entryBody}>
        <p style={{
          ...messageText,
          WebkitLineClamp: messageShort ? 4 : undefined,
          overflow: messageShort ? 'hidden' : 'visible',
          display: messageShort ? '-webkit-box' : 'block',
          WebkitBoxOrient: messageShort ? 'vertical' : undefined,
        }}>
          {entry.message}
        </p>
        {entry.message?.length > 200 && (
          <button
            type="button"
            onClick={() => setExpanded((v) => !v)}
            style={expandBtn}
          >
            {expanded ? <><ChevronUp size={12} /> Show less</> : <><ChevronDown size={12} /> Show more</>}
          </button>
        )}
      </div>

      {/* Reminder sent timestamp */}
      {entry.reminder_sent_at && (
        <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 4 }}>
          Reminder sent: {formatDateTime(entry.reminder_sent_at)}
        </div>
      )}

      {/* Resolved info */}
      {isResolved && entry.resolved_at && (
        <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 2 }}>
          Resolved {formatDateTime(entry.resolved_at)}
          {entry.resolved_by_name ? ` by ${entry.resolved_by_name}` : ''}
        </div>
      )}

      {/* Action row */}
      {(canEdit || isSuperAdmin) && (
        <div style={actionRow}>
          {actionErr && <span style={{ fontSize: 11, color: '#dc2626', flex: 1 }}>{actionErr}</span>}

          {canEdit && !isResolved && hasFollowUp && (
            <button
              type="button"
              disabled={busy}
              onClick={resolve}
              style={actionBtn}
              title="Mark as resolved"
            >
              <CheckCircle2 size={13} />
              Resolve
            </button>
          )}

          {canEdit && canRemind && (
            <button
              type="button"
              disabled={busy}
              onClick={sendReminder}
              style={actionBtn}
              title="Send reminder email to client/associate"
            >
              <Bell size={13} />
              Send Reminder
            </button>
          )}

          {canEdit && (
            <button
              type="button"
              disabled={busy}
              onClick={togglePin}
              style={actionBtn}
              title={isPinned ? 'Unpin' : 'Pin to top'}
            >
              {isPinned ? <PinOff size={13} /> : <Pin size={13} />}
              {isPinned ? 'Unpin' : 'Pin'}
            </button>
          )}

          {isSuperAdmin && (
            <button
              type="button"
              disabled={busy}
              onClick={() => setConfirmDeleteOpen(true)}
              style={{ ...actionBtn, color: '#ef4444' }}
              title="Delete log entry"
            >
              <Trash2 size={13} />
              Delete
            </button>
          )}
        </div>
      )}
    </div>
    <DestructiveConfirmModal
      open={confirmDeleteOpen}
      title="Delete log entry?"
      error={confirmDeleteOpen ? actionErr : ''}
      busy={busy}
      confirmLabel="Delete entry"
      onClose={() => !busy && setConfirmDeleteOpen(false)}
      onConfirm={handleDeleteConfirmed}
    >
      <p style={{ margin: 0, color: '#64748b', fontSize: 13 }}>
        Permanently remove this log line from the engagement activity. Audit policies may retain traces on the server.
      </p>
    </DestructiveConfirmModal>
    </>
  );
}

// ── Helpers ───────────────────────────────────────────────────────────────────
function todayStr() {
  return new Date().toISOString().slice(0, 10);
}

function formatDateTime(isoStr) {
  if (!isoStr) return '';
  try {
    const d = new Date(isoStr);
    return d.toLocaleDateString('en-IN', {
      day: '2-digit', month: 'short', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  } catch {
    return isoStr;
  }
}

// ── Styles ────────────────────────────────────────────────────────────────────
const entryWrap = {
  background: '#fff',
  border: '1px solid #E6E8F0',
  borderRadius: 10,
  padding: '14px 16px',
  display: 'flex',
  flexDirection: 'column',
  gap: 8,
};
const pinnedStyle = {
  borderColor: 'rgba(var(--portal-primary-rgb),0.35)',
  background: '#FFFDF9',
  boxShadow: '0 0 0 2px rgba(var(--portal-primary-rgb),0.08)',
};
const resolvedStyle = {
  opacity: 0.7,
  background: '#FAFCFF',
};
const entryTop = {
  display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8,
};
const typeBadge = {
  display: 'inline-flex', alignItems: 'center',
  fontSize: 11, fontWeight: 700,
  padding: '2px 8px', borderRadius: 6,
  letterSpacing: '0.02em',
};
const visBadge = {
  display: 'inline-flex', alignItems: 'center',
  fontSize: 11, fontWeight: 600,
};
const followUpChip = {
  display: 'inline-flex', alignItems: 'center',
  fontSize: 11, fontWeight: 700,
  padding: '2px 8px', borderRadius: 6,
};
const resolvedBadge = {
  display: 'inline-flex', alignItems: 'center',
  fontSize: 11, fontWeight: 600, color: '#16a34a',
  background: '#F0FDF4', border: '1px solid #bbf7d0',
  padding: '2px 8px', borderRadius: 6,
};
const entryBody = { display: 'flex', flexDirection: 'column', gap: 4 };
const messageText = {
  margin: 0, fontSize: 13, color: '#334155', lineHeight: 1.6,
  whiteSpace: 'pre-wrap', wordBreak: 'break-word',
};
const expandBtn = {
  background: 'none', border: 'none', cursor: 'pointer',
  color: 'var(--portal-primary)', fontSize: 12, fontWeight: 600,
  padding: 0, display: 'inline-flex', alignItems: 'center', gap: 3, marginTop: 2,
};
const actionRow = {
  display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap',
  paddingTop: 6, borderTop: '1px solid #F1F5F9', marginTop: 2,
};
const actionBtn = {
  display: 'inline-flex', alignItems: 'center', gap: 4,
  padding: '4px 10px', background: 'var(--portal-bg)', border: '1px solid #E6E8F0',
  borderRadius: 6, fontSize: 12, fontWeight: 600, cursor: 'pointer',
  color: '#475569',
};

