import { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ChevronRight, User, Building2, Search, X, CheckSquare, Square, Loader2 } from 'lucide-react';
import { getCategories } from '../../../services/serviceCategoryService';
import { createEngagement, toggleMasterService, linkService, ApiError } from '../../../services/engagementService';
import OpenEngagementConflictModal from '../../../components/services/OpenEngagementConflictModal';
import { getContact, getContactsForSearch } from '../../../services/contactService';
import { getOrganization, getOrganizationsForSearch } from '../../../services/organizationService';
import { useStaffUsers } from '../../../hooks/useStaffUsers';
import { useNotification } from '../../../context/NotificationContext';
import { getApprovedAssociates } from '../../../services/associateAdminService';
import DateInput from '../../../components/common/DateInput';
import { localDateKey, engagementDueDateKey } from '../../../utils/serviceKpiFilters';
import RelevantPeriodSelector from '../../../components/common/RelevantPeriodSelector';

// ── Helpers ───────────────────────────────────────────────────────────────────
function currentFY() {
  const today = new Date();
  const year = today.getFullYear();
  const month = today.getMonth() + 1; // 1-12
  // Indian FY: April (4) to March (3)
  if (month >= 4) return `${year}-${String(year + 1).slice(-2)}`;
  return `${year - 1}-${String(year).slice(-2)}`;
}

function generateId() {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return 'eng-' + crypto.randomUUID();
  }
  return 'eng-' + Date.now() + '-' + Math.random().toString(36).slice(2, 9);
}

// ── Toast ─────────────────────────────────────────────────────────────────────
function Toast({ message, onClose }) {
  return (
    <div style={toastStyle}>
      <span>{message}</span>
      <button onClick={onClose} style={toastClose}><X size={14} /></button>
    </div>
  );
}

// ── Client preview card ───────────────────────────────────────────────────────
function ClientCard({ client, type }) {
  if (!client) return null;
  const name = client.displayName;
  const sub = type === 'contact'
    ? (client.city ? `📍 ${client.city}` : '')
    : (client.constitution ? client.constitution : '');
  const extra = type === 'contact'
    ? (client.linkedOrgsCount > 0 ? `${client.linkedOrgsCount} linked org${client.linkedOrgsCount > 1 ? 's' : ''}` : null)
    : (client.primaryContact && client.primaryContact !== '—' ? `Contact: ${client.primaryContact}` : null);
  return (
    <div style={clientCardStyle}>
      <div style={clientCardAvatar}>{name[0]}</div>
      <div style={{ minWidth: 0 }}>
        <div style={{ fontWeight: 700, fontSize: 13, color: '#0B1F3B', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{name}</div>
        {sub && <div style={{ fontSize: 11, color: '#64748b', marginTop: 2 }}>{sub}</div>}
        {extra && <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 1 }}>{extra}</div>}
      </div>
    </div>
  );
}

// ── Server-backed client search (full directory; list API is paginated) ───────
const ORG_SEARCH_MIN_LEN = 2;
const CONTACT_SEARCH_MIN_LEN = 1;
const CLIENT_SEARCH_LIMIT = 50;
const CLIENT_SEARCH_DEBOUNCE_MS = 300;

function AsyncClientSearchDropdown({ clientType, value, displayName, onSelect, placeholder }) {
  const [query, setQuery] = useState('');
  const [open, setOpen] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const [loading, setLoading] = useState(false);
  const debounceRef = useRef(null);

  const minLen = clientType === 'organization' ? ORG_SEARCH_MIN_LEN : CONTACT_SEARCH_MIN_LEN;
  const hasSelection = Boolean(value && displayName);

  const runSearch = useCallback(async (q) => {
    const trimmed = q.trim();
    if (trimmed.length < minLen) {
      setSuggestions([]);
      return;
    }
    setLoading(true);
    try {
      const rows = clientType === 'organization'
        ? await getOrganizationsForSearch(trimmed, CLIENT_SEARCH_LIMIT)
        : await getContactsForSearch(trimmed, CLIENT_SEARCH_LIMIT);
      setSuggestions(rows);
    } catch {
      setSuggestions([]);
    } finally {
      setLoading(false);
    }
  }, [clientType, minLen]);

  useEffect(() => () => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
  }, []);

  function handleInput(e) {
    const val = e.target.value;
    setQuery(val);
    setOpen(true);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => runSearch(val), CLIENT_SEARCH_DEBOUNCE_MS);
    if (val.trim().length < minLen) setSuggestions([]);
  }

  function selectRow(row) {
    onSelect(row.id, row.displayName);
    setQuery('');
    setSuggestions([]);
    setOpen(false);
  }

  function clear(e) {
    e.stopPropagation();
    onSelect('', '');
    setQuery('');
    setSuggestions([]);
  }

  return (
    <div style={{ position: 'relative' }}>
      <div
        style={{ ...searchDropdownBox, borderColor: open ? 'var(--portal-primary)' : '#E6E8F0' }}
        onClick={() => setOpen(v => !v)}
      >
        <Search size={13} color="#94a3b8" style={{ flexShrink: 0 }} />
        <input
          style={searchDropdownInput}
          placeholder={hasSelection ? displayName : placeholder}
          value={open ? query : ''}
          onChange={handleInput}
          onFocus={() => { setOpen(true); }}
          onClick={e => e.stopPropagation()}
        />
        {hasSelection && (
          <button type="button" onClick={clear} style={searchDropdownClear}>
            <X size={12} />
          </button>
        )}
      </div>
      {open && (
        <div style={searchDropdownMenu}>
          {loading && (
            <div style={searchDropdownEmpty}>Searching…</div>
          )}
          {!loading && (() => {
            const t = query.trim();
            if (t.length === 0) {
              return (
                <div style={searchDropdownEmpty}>
                  {clientType === 'organization'
                    ? 'Type at least 2 characters to search all organizations.'
                    : 'Type at least 1 character to search all contacts.'}
                </div>
              );
            }
            if (t.length < minLen) {
              return (
                <div style={searchDropdownEmpty}>
                  {clientType === 'organization'
                    ? 'Type at least 2 characters to search organizations…'
                    : 'Keep typing to search contacts…'}
                </div>
              );
            }
            if (suggestions.length === 0) {
              return <div style={searchDropdownEmpty}>No results found</div>;
            }
            return suggestions.map(item => (
              <div
                key={item.id}
                style={{ ...searchDropdownItem, background: String(item.id) === String(value) ? 'var(--portal-primary-tint)' : undefined }}
                onClick={() => selectRow(item)}
                onMouseEnter={e => { if (String(item.id) !== String(value)) e.currentTarget.style.background = 'var(--portal-bg)'; }}
                onMouseLeave={e => { if (String(item.id) !== String(value)) e.currentTarget.style.background = ''; }}
              >
                <div style={{ fontWeight: 600, fontSize: 13, color: '#0B1F3B' }}>{item.displayName}</div>
                {item.city && <div style={{ fontSize: 11, color: '#94a3b8' }}>{item.city}</div>}
              </div>
            ));
          })()}
        </div>
      )}
      {open && <div style={overlay} onClick={() => setOpen(false)} />}
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────
const COMMISSION_MODE_LABELS = {
  referral_only: 'Referral only (tiered %)',
  direct_interaction: 'Direct interaction (50/50 split)',
};

export default function NewServiceEngagement() {
  const navigate = useNavigate();
  const location = useLocation();
  const { addNotification } = useNotification();

  // Parent service context — set when navigated from "Add Child Service"
  const parentServiceId = location.state?.parentServiceId ?? null;
  const parentServiceName = location.state?.parentServiceName ?? null;
  const parentIsMaster = location.state?.parentIsMaster ?? false;
  const parentClientType = location.state?.parentClientType ?? null;
  const parentClientId = location.state?.parentClientId ?? null;
  const parentClientName = location.state?.parentClientName ?? null;
  const parentFinancialYear = location.state?.parentFinancialYear ?? null;
  const returnUrl = location.state?.returnUrl ?? '/services';

  // Catalog loaded from API
  const [categories, setCategories] = useState([]);
  /** loading | ready | error — avoids showing “configure Settings” when the request failed */
  const [catalogStatus, setCatalogStatus] = useState('loading');
  const [catalogErrorMessage, setCatalogErrorMessage] = useState('');
  const hasCatalog = categories.length > 0;

  const loadCatalog = useCallback(() => {
    setCatalogStatus('loading');
    setCatalogErrorMessage('');
    getCategories()
      .then((cats) => {
        setCategories(Array.isArray(cats) ? cats : []);
        setCatalogStatus('ready');
      })
      .catch((err) => {
        setCategories([]);
        setCatalogErrorMessage(err?.message || 'Failed to load service catalog.');
        setCatalogStatus('error');
      });
  }, []);

  useEffect(() => {
    loadCatalog();
  }, [loadCatalog]);

  // Client selection (search-backed; no bulk list — API is paginated at 100/page)
  const [clientType, setClientType] = useState('contact'); // 'contact' | 'organization'
  const [clientId, setClientId] = useState('');
  const [selectedClientLabel, setSelectedClientLabel] = useState('');

  // Service catalog selection
  const [categoryId, setCategoryId] = useState('');
  const [subcategoryId, setSubcategoryId] = useState('');
  const [engagementTypeId, setEngagementTypeId] = useState('');

  // Other fields
  const [fy, setFy] = useState(currentFY());
  const [relevantPeriod, setRelevantPeriod] = useState({ frequency: '', from: '', to: '', label: '' });
  const [assignedTo, setAssignedTo] = useState('');
  const [dueDate, setDueDate] = useState('');
  const [status, setStatus] = useState('not_started');
  const [fee, setFee] = useState('');
  const [notes, setNotes] = useState('');
  const [createChecklist, setCreateChecklist] = useState(false);
  const [markAsMaster, setMarkAsMaster] = useState(false);

  const [masterClient, setMasterClient] = useState(null);
  const [approvedAssociates, setApprovedAssociates] = useState([]);

  // UI state
  const [errors, setErrors] = useState({});
  const [toast, setToast] = useState('');
  const [saving, setSaving] = useState(false);
  const [openEngagementConflict, setOpenEngagementConflict] = useState(null);

  // Dynamic staff list
  const { staffUsers } = useStaffUsers();

  useEffect(() => {
    getApprovedAssociates()
      .then(setApprovedAssociates)
      .catch(() => setApprovedAssociates([]));
  }, []);

  // Pre-fill client and FY when creating a child service from an existing engagement
  useEffect(() => {
    if (!parentServiceId) return;
    if (parentClientType && parentClientId) {
      setClientType(parentClientType);
      setClientId(String(parentClientId));
      if (parentClientName) setSelectedClientLabel(parentClientName);
    }
    if (parentFinancialYear) setFy(parentFinancialYear);
  }, [parentServiceId, parentClientType, parentClientId, parentClientName, parentFinancialYear]);

  useEffect(() => {
    if (!clientId) {
      setMasterClient(null);
      return;
    }
    const req = clientType === 'contact'
      ? getContact(clientId)
      : getOrganization(clientId);
    req.then(setMasterClient).catch(() => setMasterClient(null));
  }, [clientId, clientType]);

  useEffect(() => {
    if (masterClient?.displayName && clientId) {
      setSelectedClientLabel(masterClient.displayName);
    }
  }, [masterClient?.displayName, clientId]);

  // ── Derived catalog data ────────────────────────────────────────────────────
  const selectedCategory = categories.find(c => String(c.id) === String(categoryId));
  const subcategories = selectedCategory?.subcategories ?? [];

  const selectedSubcategory = subcategories.find(s => String(s.id) === String(subcategoryId));
  // Only show engagement types that belong to the selected subcategory
  const engagementTypes = selectedSubcategory?.engagementTypes ?? [];

  const selectedEngagementType = engagementTypes.find(e => String(e.id) === String(engagementTypeId));

  const referralAssociateLabel = useMemo(() => {
    if (!masterClient) return 'Select a client to see referral details.';
    const aid = masterClient.referringAssociateUserId;
    if (!aid) return 'None';
    const a = approvedAssociates.find((x) => String(x.id) === String(aid));
    return a ? `${a.name} (${a.email})` : `Linked user #${aid}`;
  }, [masterClient, approvedAssociates]);

  const referralCommissionLabel = useMemo(() => {
    if (!masterClient) return '—';
    const m = masterClient.commissionMode || 'referral_only';
    return COMMISSION_MODE_LABELS[m] || m;
  }, [masterClient]);

  const referralClientFacingNote = useMemo(() => {
    if (!masterClient) return '';
    return masterClient.clientFacingRestricted
      ? 'Client master default: client-facing restricted (applied when this engagement is created).'
      : 'Client master default: not restricted (applied when this engagement is created).';
  }, [masterClient]);

  // ── Selected client row (detail loaded async into masterClient) ─────────────
  const selectedClient = masterClient
    || (clientId && selectedClientLabel ? { displayName: selectedClientLabel } : null);

  // ── Cascade reset helpers ───────────────────────────────────────────────────
  function handleCategoryChange(id) {
    setCategoryId(id);
    setSubcategoryId('');
    setEngagementTypeId('');
  }

  function handleSubcategoryChange(id) {
    setSubcategoryId(id);
    setEngagementTypeId('');
  }

  function handleClientTypeChange(type) {
    setClientType(type);
    setClientId('');
    setSelectedClientLabel('');
  }

  function handleClientSelect(id, name) {
    const sid = id === '' || id == null ? '' : String(id);
    setClientId(sid);
    setSelectedClientLabel(name || '');
    setErrors(prev => ({ ...prev, clientId: '' }));
  }

  // ── Validation ──────────────────────────────────────────────────────────────
  function validate() {
    const e = {};
    if (!clientId) e.clientId = 'Please select a client.';
    if (!categoryId) e.categoryId = 'Category is required.';
    if (!subcategoryId) e.subcategoryId = 'Subcategory is required.';
    if (!engagementTypeId) e.engagementTypeId = 'Engagement Type is required.';
    if (!assignedTo) e.assignedTo = 'Assigned To is required.';
    if (!dueDate) e.dueDate = 'Due Date is required.';
    else {
      const dk = engagementDueDateKey(dueDate);
      const todayKey = localDateKey(new Date());
      if (dk && dk < todayKey) e.dueDate = 'Due date cannot be in the past.';
    }
    return e;
  }

  // ── Submit ──────────────────────────────────────────────────────────────────
  function handleCreate() {
    const e = validate();
    if (Object.keys(e).length > 0) {
      setErrors(e);
      // Scroll to first error
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }
    setErrors({});

    const checklist = (createChecklist && selectedEngagementType?.defaultChecklist)
      ? selectedEngagementType.defaultChecklist.map((title, idx) => ({
          id: `task-${generateId()}-${idx}`,
          title,
          status: 'pending',
          assignedTo: assignedTo,
          dueDate: dueDate,
          priority: 'medium',
        }))
      : [];

    const engagement = {
      clientType,
      clientId,
      clientName: masterClient?.displayName || selectedClientLabel || selectedClient?.displayName || '',
      categoryId,
      categoryName: selectedCategory.name,
      subcategoryId,
      subcategoryName: selectedSubcategory ? selectedSubcategory.name : '',
      engagementTypeId,
      engagementTypeName: selectedEngagementType.name,
      type: `${selectedCategory.name} – ${selectedEngagementType.name}`,
      financialYear: fy,
      relevantPeriodFrequency: relevantPeriod.frequency || null,
      relevantPeriodFrom: relevantPeriod.from || null,
      relevantPeriodTo: relevantPeriod.to || null,
      relevantPeriodLabel: relevantPeriod.label || null,
      assignedTo,
      dueDate,
      status,
      feeAgreed: fee ? Number(fee) : null,
      notes,
      tasks: checklist,
    };

    setSaving(true);
    createEngagement(engagement)
      .then(async (newEngagement) => {
        if (parentServiceId && newEngagement?.id) {
          try {
            if (!parentIsMaster) {
              await toggleMasterService(parentServiceId, true);
            }
            await linkService(parentServiceId, newEngagement.id);
            addNotification('Child service created and linked to master', 'service');
            setToast('Child service created and linked');
          } catch (linkErr) {
            addNotification('New service engagement created', 'service');
            setToast('Service created, but linking failed: ' + (linkErr.message || 'Unknown error'));
          }
        } else if (markAsMaster && newEngagement?.id) {
          try {
            await toggleMasterService(newEngagement.id, true);
            addNotification('New master service engagement created', 'service');
            setToast('Engagement created as Master Service');
          } catch {
            addNotification('New service engagement created', 'service');
            setToast('Engagement created (could not mark as master)');
          }
        } else {
          addNotification('New service engagement created', 'service');
          setToast('Engagement created');
        }
        setTimeout(() => navigate(returnUrl), 1200);
      })
      .catch(err => {
        if (err instanceof ApiError && err.status === 409 && err.body?.data?.existing) {
          setOpenEngagementConflict(err.body.data.existing);
          return;
        }
        setToast('Error: ' + (err.message || 'Failed to create engagement.'));
      })
      .finally(() => setSaving(false));
  }

  function handleCancel() {
    navigate(returnUrl);
  }

  // ── Render ──────────────────────────────────────────────────────────────────
  return (
    <div style={pageWrap}>
      <OpenEngagementConflictModal
        open={Boolean(openEngagementConflict)}
        existing={openEngagementConflict}
        onClose={() => setOpenEngagementConflict(null)}
      />
      {toast && <Toast message={toast} onClose={() => setToast('')} />}

      {/* Breadcrumb */}
      <div style={breadcrumbRow}>
        <span style={crumb} onClick={() => navigate('/')} role="button" tabIndex={0} onKeyDown={e => (e.key === 'Enter' || e.key === ' ') && navigate('/')}>Home</span>
        <ChevronRight size={13} color="#94a3b8" />
        <span style={crumb} onClick={() => navigate('/services')} role="button" tabIndex={0} onKeyDown={e => (e.key === 'Enter' || e.key === ' ') && navigate('/services')}>Services &amp; Tasks</span>
        <ChevronRight size={13} color="#94a3b8" />
        <span style={crumbActive}>New Service Engagement</span>
      </div>

      <div style={pageTitle}>New Service Engagement</div>

      {parentServiceId && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 14px', marginBottom: 16, background: 'var(--portal-primary-tint)', border: '1px solid rgba(var(--portal-primary-rgb),0.35)', borderRadius: 8 }}>
          <span style={{ fontSize: 13, color: '#C25A0A', fontWeight: 600 }}>Creating as child service of:</span>
          <span style={{ fontSize: 13, color: '#0B1F3B', fontWeight: 700 }}>{parentServiceName || `Service #${parentServiceId}`}</span>
          <span style={{ fontSize: 11, color: '#64748b', marginLeft: 'auto' }}>The parent will be marked as master and this service will be linked to it on save.</span>
        </div>
      )}

      {catalogStatus === 'loading' && (
        <div style={{ ...emptyCatalogCard, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12 }}>
          <Loader2 size={28} color="var(--portal-primary)" style={{ animation: 'spin 0.8s linear infinite' }} />
          <div style={{ fontSize: 14, color: '#64748b' }}>Loading service catalog…</div>
        </div>
      )}

      {catalogStatus === 'error' && (
        <div style={{ ...emptyCatalogCard, borderColor: '#fecaca', background: '#fef2f2' }}>
          <div style={{ fontWeight: 700, fontSize: 15, color: '#991b1b', marginBottom: 8 }}>Could not load service catalog</div>
          <div style={{ fontSize: 13, color: '#7f1d1d', marginBottom: 14 }}>{catalogErrorMessage}</div>
          <div style={{ fontSize: 12, color: '#64748b', marginBottom: 18, lineHeight: 1.5 }}>
            Check your connection or sign in again if your session expired. If this persists, confirm the deployed <code style={{ fontSize: 11 }}>VITE_API_BASE_URL</code> matches the same API root your browser already uses for other working requests (compare any successful request under <code style={{ fontSize: 11 }}>/admin/</code> in DevTools → Network).
          </div>
          <div style={{ display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap' }}>
            <button type="button" style={btnPrimary} onClick={loadCatalog}>Retry</button>
            <button type="button" style={btnSecondary} onClick={() => navigate('/settings')}>Open Settings</button>
          </div>
        </div>
      )}

      {catalogStatus === 'ready' && !hasCatalog && (
        <div style={emptyCatalogCard}>
          <div style={{ fontSize: 22, marginBottom: 8 }}>⚙️</div>
          <div style={{ fontWeight: 700, fontSize: 15, color: '#0B1F3B', marginBottom: 4 }}>No Service Catalog configured yet.</div>
          <div style={{ fontSize: 13, color: '#64748b', marginBottom: 18 }}>
            Add categories, subcategories, and engagement types under Settings → Service Configuration before creating an engagement.
          </div>
          <button type="button" style={btnPrimary} onClick={() => navigate('/settings')}>Open Settings</button>
        </div>
      )}

      {catalogStatus === 'ready' && hasCatalog && (
        <div style={formGrid}>
          {/* ── Section: Client ─────────────────────────────────────────── */}
          <FormSection title="Client Selection">
            {/* Toggle */}
            <div style={{ display: 'flex', gap: 0, marginBottom: 16 }}>
              <ToggleButton
                active={clientType === 'contact'}
                onClick={() => handleClientTypeChange('contact')}
                icon={<User size={14} />}
                label="Person (Contact)"
                side="left"
              />
              <ToggleButton
                active={clientType === 'organization'}
                onClick={() => handleClientTypeChange('organization')}
                icon={<Building2 size={14} />}
                label="Organization"
                side="right"
              />
            </div>

            <FieldLabel label="Select Client" required />
            <AsyncClientSearchDropdown
              clientType={clientType}
              value={clientId}
              displayName={selectedClientLabel}
              onSelect={handleClientSelect}
              placeholder={`Search ${clientType === 'contact' ? 'contact' : 'organization'}…`}
            />
            {errors.clientId && <ErrorMsg msg={errors.clientId} />}

            {selectedClient && (
              <div style={{ marginTop: 12 }}>
                <ClientCard client={selectedClient} type={clientType} />
              </div>
            )}
          </FormSection>

          {/* ── Section: Service ────────────────────────────────────────── */}
          <FormSection title="Service Details">
            <FieldLabel label="Category" required />
            <select
              value={categoryId}
              onChange={e => { handleCategoryChange(e.target.value); setErrors(prev => ({ ...prev, categoryId: '' })); }}
              style={{ ...selectStyle, borderColor: errors.categoryId ? '#ef4444' : '#E6E8F0' }}
            >
              <option value="">Select category…</option>
              {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            {errors.categoryId && <ErrorMsg msg={errors.categoryId} />}

            <FieldLabel label="Subcategory" required style={{ marginTop: 14 }} />
            <select
              value={subcategoryId}
              onChange={e => { handleSubcategoryChange(e.target.value); setErrors(prev => ({ ...prev, subcategoryId: '' })); }}
              style={{ ...selectStyle, borderColor: errors.subcategoryId ? '#ef4444' : '#E6E8F0' }}
              disabled={!categoryId}
            >
              <option value="">
                {categoryId ? 'Select subcategory…' : '← Select a category first'}
              </option>
              {subcategories.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
            {errors.subcategoryId && <ErrorMsg msg={errors.subcategoryId} />}

            <FieldLabel label="Engagement Type" required style={{ marginTop: 14 }} />
            <select
              value={engagementTypeId}
              onChange={e => { setEngagementTypeId(e.target.value); setErrors(prev => ({ ...prev, engagementTypeId: '' })); }}
              style={{ ...selectStyle, borderColor: errors.engagementTypeId ? '#ef4444' : '#E6E8F0' }}
              disabled={!subcategoryId}
            >
              <option value="">
                {subcategoryId ? 'Select engagement type…' : '← Select a subcategory first'}
              </option>
              {engagementTypes.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
            </select>
            {errors.engagementTypeId && <ErrorMsg msg={errors.engagementTypeId} />}
          </FormSection>

          {/* ── Section: Referral & commission (from client master; read-only here) ─ */}
          <FormSection title="Referral &amp; commission">
            <p style={{ fontSize: 12, color: '#64748b', margin: '0 0 12px', lineHeight: 1.45 }}>
              Referring associate, commission mode, and referral start date are set on the <strong>contact or organization</strong> record. They are copied into this engagement when it is created and cannot be changed here.
            </p>
            <FieldLabel label="Referring associate" />
            <div style={{ ...inputStyle, background: '#f8fafc', color: '#334155', cursor: 'default' }}>{referralAssociateLabel}</div>
            <FieldLabel label="Commission mode" style={{ marginTop: 14 }} />
            <div style={{ ...inputStyle, background: '#f8fafc', color: '#334155', cursor: 'default' }}>{referralCommissionLabel}</div>
            {referralClientFacingNote && (
              <p style={{ fontSize: 12, color: '#64748b', margin: '14px 0 0', lineHeight: 1.45 }}>{referralClientFacingNote}</p>
            )}
          </FormSection>

          {/* ── Section: Engagement Details ─────────────────────────────── */}
          <FormSection title="Engagement Details">
            <div style={{ marginBottom: 14 }}>
              <FieldLabel label="Relevant Period" />
              <RelevantPeriodSelector
                frequency={relevantPeriod.frequency}
                periodFrom={relevantPeriod.from}
                periodTo={relevantPeriod.to}
                periodLabel={relevantPeriod.label}
                onChange={setRelevantPeriod}
              />
            </div>

            <div style={twoCol}>
              <div>
                <FieldLabel label="Financial Year" />
                <input
                  value={fy}
                  onChange={e => setFy(e.target.value)}
                  style={inputStyle}
                  placeholder="e.g. 2025-26"
                />
              </div>
              <div>
                <FieldLabel label="Status" />
                <select value={status} onChange={e => setStatus(e.target.value)} style={selectStyle}>
                  <option value="not_started">Not Started</option>
                  <option value="in_progress">In Progress</option>
                  <option value="pending_info">Pending Info</option>
                  <option value="completed">Completed</option>
                </select>
              </div>
            </div>

            <div style={{ ...twoCol, marginTop: 14 }}>
              <div>
                <FieldLabel label="Assigned To" required />
                <select
                  value={assignedTo}
                  onChange={e => { setAssignedTo(e.target.value); setErrors(prev => ({ ...prev, assignedTo: '' })); }}
                  style={{ ...selectStyle, borderColor: errors.assignedTo ? '#ef4444' : '#E6E8F0' }}
                >
                  <option value="">Select staff…</option>
                  {staffUsers.map(s => (
                    <option key={s.id} value={String(s.id)}>{s.name}</option>
                  ))}
                </select>
                {errors.assignedTo && <ErrorMsg msg={errors.assignedTo} />}
              </div>
              <div>
                <FieldLabel label="Due Date" required />
                <DateInput
                  min={localDateKey(new Date())}
                  value={dueDate}
                  onChange={e => { setDueDate(e.target.value); setErrors(prev => ({ ...prev, dueDate: '' })); }}
                  style={{ ...inputStyle, borderColor: errors.dueDate ? '#ef4444' : '#E6E8F0' }}
                />
                {errors.dueDate && <ErrorMsg msg={errors.dueDate} />}
              </div>
            </div>

            <div style={{ marginTop: 14 }}>
              <FieldLabel label="Fee (₹)" />
              <div style={feeWrap}>
                <span style={feePrefix}>₹</span>
                <input
                  type="number"
                  min="0"
                  value={fee}
                  onChange={e => setFee(e.target.value)}
                  placeholder="0"
                  style={{ ...inputStyle, borderRadius: '0 8px 8px 0', borderLeft: 'none', paddingLeft: 8 }}
                />
              </div>
            </div>

            <div style={{ marginTop: 14 }}>
              <FieldLabel label="Notes" />
              <textarea
                value={notes}
                onChange={e => setNotes(e.target.value)}
                rows={3}
                placeholder="Optional notes…"
                style={textareaStyle}
              />
            </div>

            {/* Checklist checkbox */}
            {selectedEngagementType?.defaultChecklist?.length > 0 && (
              <div
                style={checklistToggle}
                onClick={() => setCreateChecklist(v => !v)}
                role="checkbox"
                aria-checked={createChecklist}
                tabIndex={0}
                onKeyDown={e => e.key === ' ' && setCreateChecklist(v => !v)}
              >
                {createChecklist
                  ? <CheckSquare size={18} color="var(--portal-primary)" />
                  : <Square size={18} color="#94a3b8" />
                }
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13, color: '#0B1F3B' }}>
                    Create starter task checklist
                  </div>
                  <div style={{ fontSize: 11, color: '#64748b', marginTop: 2 }}>
                    Generates {selectedEngagementType.defaultChecklist.length} suggested tasks based on "{selectedEngagementType.name}"
                  </div>
                </div>
              </div>
            )}

            {/* Checklist preview */}
            {createChecklist && selectedEngagementType?.defaultChecklist?.length > 0 && (
              <div style={checklistPreview}>
                {selectedEngagementType.defaultChecklist.map((task, i) => (
                  <div key={i} style={checklistItem}>
                    <div style={taskDot} />
                    <span style={{ fontSize: 12, color: '#334155' }}>{task}</span>
                  </div>
                ))}
              </div>
            )}

            {/* Mark as Master Service toggle — hidden when this is already being created as a child */}
            {!parentServiceId && (
              <div
                style={{ ...checklistToggle, marginTop: 8 }}
                onClick={() => setMarkAsMaster(v => !v)}
                role="checkbox"
                aria-checked={markAsMaster}
                tabIndex={0}
                onKeyDown={e => e.key === ' ' && setMarkAsMaster(v => !v)}
              >
                {markAsMaster
                  ? <CheckSquare size={18} color="var(--portal-primary)" />
                  : <Square size={18} color="#94a3b8" />
                }
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13, color: '#0B1F3B' }}>
                    Mark as Master Service
                  </div>
                  <div style={{ fontSize: 11, color: '#64748b', marginTop: 2 }}>
                    This service will act as an umbrella for other related child services
                  </div>
                </div>
              </div>
            )}
          </FormSection>
        </div>
      )}

      {/* Action buttons */}
      <div style={actionRow}>
        <button style={btnSecondary} onClick={handleCancel}>Cancel</button>
        {catalogStatus === 'ready' && hasCatalog && (
          <button style={btnPrimary} disabled={saving} onClick={handleCreate}>{saving ? 'Saving…' : 'Create Engagement'}</button>
        )}
      </div>
    </div>
  );
}

// ── Small components ──────────────────────────────────────────────────────────
function FormSection({ title, children }) {
  return (
    <div style={sectionCard}>
      <div style={sectionTitle}>{title}</div>
      {children}
    </div>
  );
}

function FieldLabel({ label, required, style: extra }) {
  return (
    <div style={{ fontSize: 12, fontWeight: 600, color: '#475569', marginBottom: 6, ...extra }}>
      {label}
      {required && <span style={{ color: '#ef4444', marginLeft: 2 }}>*</span>}
    </div>
  );
}

function ErrorMsg({ msg }) {
  return <div style={{ fontSize: 11, color: '#ef4444', marginTop: 4 }}>{msg}</div>;
}

function ToggleButton({ active, onClick, icon, label, side }) {
  const radius = side === 'left'
    ? { borderRadius: '8px 0 0 8px' }
    : { borderRadius: '0 8px 8px 0' };
  return (
    <button
      onClick={onClick}
      style={{
        display: 'flex', alignItems: 'center', gap: 6,
        padding: '8px 18px',
        border: `1.5px solid ${active ? 'var(--portal-primary)' : '#E6E8F0'}`,
        background: active ? 'var(--portal-primary-tint)' : '#fff',
        color: active ? '#C25A0A' : '#64748b',
        fontWeight: active ? 700 : 500,
        fontSize: 13,
        cursor: 'pointer',
        ...radius,
      }}
    >
      {icon}
      {label}
    </button>
  );
}

// ── Styles ────────────────────────────────────────────────────────────────────
const pageWrap = { padding: '24px', display: 'flex', flexDirection: 'column', gap: 20, background: 'var(--portal-bg)', minHeight: '100%' };
const breadcrumbRow = { display: 'flex', alignItems: 'center', gap: 4, flexWrap: 'wrap' };
const crumb = { fontSize: 12, color: '#94a3b8', fontWeight: 500, cursor: 'pointer', textDecoration: 'none' };
const crumbActive = { fontSize: 12, color: 'var(--portal-primary)', fontWeight: 600 };
const pageTitle = { fontSize: 22, fontWeight: 700, color: '#0B1F3B', lineHeight: 1.2 };

const emptyCatalogCard = {
  background: '#fff', border: '1px solid #E6E8F0', borderRadius: 14,
  padding: '40px 24px', textAlign: 'center',
  boxShadow: '0 1px 4px rgba(0,0,0,0.05)',
};

const formGrid = { display: 'flex', flexDirection: 'column', gap: 16 };
const sectionCard = {
  background: '#fff', borderRadius: 14, border: '1px solid #E6E8F0',
  padding: '20px 24px', boxShadow: '0 1px 4px rgba(0,0,0,0.04)',
};
const sectionTitle = { fontSize: 14, fontWeight: 700, color: '#0B1F3B', marginBottom: 16, paddingBottom: 12, borderBottom: '1px solid #F0F2F8' };

const twoCol = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 };

const inputStyle = {
  width: '100%', padding: '8px 12px', border: '1px solid #E6E8F0', borderRadius: 8,
  fontSize: 13, color: '#334155', outline: 'none', background: '#fff', boxSizing: 'border-box',
};
const selectStyle = {
  width: '100%', padding: '8px 12px', border: '1px solid #E6E8F0', borderRadius: 8,
  fontSize: 13, color: '#334155', outline: 'none', background: '#fff', cursor: 'pointer', boxSizing: 'border-box',
};
const textareaStyle = {
  width: '100%', padding: '8px 12px', border: '1px solid #E6E8F0', borderRadius: 8,
  fontSize: 13, color: '#334155', outline: 'none', background: '#fff',
  resize: 'vertical', fontFamily: 'inherit', boxSizing: 'border-box',
};

const feeWrap = { display: 'flex', alignItems: 'center' };
const feePrefix = {
  padding: '8px 10px', background: 'var(--portal-bg)', border: '1px solid #E6E8F0',
  borderRight: 'none', borderRadius: '8px 0 0 8px', fontSize: 13, color: '#64748b', fontWeight: 600, flexShrink: 0,
};

const clientCardStyle = {
  display: 'flex', alignItems: 'center', gap: 10,
  background: 'var(--portal-bg)', border: '1px solid #E6E8F0',
  borderRadius: 10, padding: '10px 14px', maxWidth: 420,
};
const clientCardAvatar = {
  width: 34, height: 34, borderRadius: 9,
  background: 'linear-gradient(135deg, var(--portal-primary) 0%, var(--portal-primary-light) 100%)',
  color: '#fff', fontWeight: 700, fontSize: 13,
  display: 'flex', alignItems: 'center', justifyContent: 'center',
  flexShrink: 0,
};

const searchDropdownBox = {
  display: 'flex', alignItems: 'center', gap: 8,
  border: '1.5px solid #E6E8F0', borderRadius: 8,
  padding: '7px 10px', background: '#fff', cursor: 'text', position: 'relative',
};
const searchDropdownInput = {
  border: 'none', outline: 'none', fontSize: 13, color: '#334155',
  background: 'transparent', flex: 1, minWidth: 0,
};
const searchDropdownClear = {
  background: 'none', border: 'none', cursor: 'pointer',
  color: '#94a3b8', padding: 0, display: 'flex', alignItems: 'center',
};
const searchDropdownMenu = {
  position: 'absolute', top: 'calc(100% + 4px)', left: 0, right: 0, zIndex: 200,
  background: '#fff', border: '1px solid #E6E8F0', borderRadius: 10,
  boxShadow: '0 8px 24px rgba(0,0,0,0.10)', maxHeight: 220, overflowY: 'auto',
};
const searchDropdownItem = {
  padding: '8px 12px', cursor: 'pointer', transition: 'background 0.1s',
};
const searchDropdownEmpty = { padding: '12px', fontSize: 13, color: '#94a3b8', textAlign: 'center' };
const overlay = { position: 'fixed', inset: 0, zIndex: 199 };

const checklistToggle = {
  display: 'flex', alignItems: 'flex-start', gap: 10,
  background: 'var(--portal-bg)', border: '1px solid #E6E8F0', borderRadius: 10,
  padding: '12px 14px', cursor: 'pointer', marginTop: 16, userSelect: 'none',
};
const checklistPreview = {
  background: '#F8FAFC', border: '1px solid #E6E8F0', borderRadius: 10,
  padding: '12px 14px', marginTop: 8, display: 'flex', flexDirection: 'column', gap: 6,
};
const checklistItem = { display: 'flex', alignItems: 'center', gap: 8 };
const taskDot = { width: 7, height: 7, borderRadius: '50%', background: '#cbd5e1', flexShrink: 0 };

const actionRow = {
  display: 'flex', justifyContent: 'flex-end', alignItems: 'center', gap: 10,
  paddingTop: 4,
};
const btnPrimary = {
  display: 'flex', alignItems: 'center', gap: 6, padding: '10px 22px',
  background: 'var(--portal-primary)', color: '#fff', border: 'none', borderRadius: 8,
  cursor: 'pointer', fontSize: 14, fontWeight: 600,
  boxShadow: '0 2px 8px rgba(var(--portal-primary-rgb),0.30)',
};
const btnSecondary = {
  display: 'flex', alignItems: 'center', gap: 6, padding: '10px 18px',
  background: '#fff', color: '#64748b', border: '1px solid #E6E8F0', borderRadius: 8,
  cursor: 'pointer', fontSize: 14, fontWeight: 600,
};

const toastStyle = {
  position: 'fixed', bottom: 28, right: 28, zIndex: 9999,
  display: 'flex', alignItems: 'center', gap: 12,
  background: '#0B1F3B', color: '#fff', padding: '12px 18px',
  borderRadius: 10, boxShadow: '0 4px 20px rgba(0,0,0,0.20)',
  fontSize: 13, fontWeight: 600,
};
const toastClose = {
  background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer',
  display: 'flex', alignItems: 'center', padding: 0,
};

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { CheckCircle2, Bell, AlertTriangle, Clock, CalendarDays, ExternalLink } from 'lucide-react';
import {
  getPendingFollowUps,
  updateServiceLog,
  sendLogReminder,
} from '../services/serviceLogService';

const DAYS_AHEAD = 30;

// ── Helpers ───────────────────────────────────────────────────────────────────
function todayStr() {
  return new Date().toISOString().slice(0, 10);
}

function formatDate(d) {
  if (!d) return '—';
  try {
    return new Date(d + 'T00:00:00').toLocaleDateString('en-IN', {
      day: '2-digit', month: 'short', year: 'numeric',
    });
  } catch { return d; }
}

function formatDateTime(iso) {
  if (!iso) return '—';
  try {
    return new Date(iso).toLocaleDateString('en-IN', {
      day: '2-digit', month: 'short', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  } catch { return iso; }
}

function classifyEntry(entry) {
  const today = todayStr();
  if (!entry.follow_up_date) return 'other';
  if (entry.follow_up_date < today)  return 'overdue';
  if (entry.follow_up_date === today) return 'today';
  return 'upcoming';
}

// ── Main component ────────────────────────────────────────────────────────────
export default function PendingFollowUps() {
  const navigate  = useNavigate();
  const [rows, setRows]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');
  const [busy, setBusy]       = useState({});
  const [actionMsg, setActionMsg] = useState({});

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const data = await getPendingFollowUps({ daysAhead: DAYS_AHEAD });
      setRows(data);
    } catch (e) {
      setError(e.message || 'Failed to load pending follow-ups.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  async function handleResolve(entry) {
    const key = `resolve-${entry.id}`;
    setBusy((b) => ({ ...b, [key]: true }));
    try {
      await updateServiceLog(entry.service_id, entry.id, { resolve: true });
      setRows((prev) => prev.filter((r) => r.id !== entry.id));
      setActionMsg((m) => ({ ...m, [entry.id]: 'Resolved.' }));
    } catch (e) {
      setActionMsg((m) => ({ ...m, [entry.id]: e.message || 'Failed.' }));
    } finally {
      setBusy((b) => ({ ...b, [key]: false }));
    }
  }

  async function handleRemind(entry) {
    const key = `remind-${entry.id}`;
    setBusy((b) => ({ ...b, [key]: true }));
    try {
      const updated = await sendLogReminder(entry.service_id, entry.id);
      setRows((prev) => prev.map((r) => r.id === entry.id ? { ...r, reminder_sent_at: updated?.reminder_sent_at } : r));
      setActionMsg((m) => ({ ...m, [entry.id]: 'Reminder sent!' }));
    } catch (e) {
      setActionMsg((m) => ({ ...m, [entry.id]: e.message || 'Failed to send.' }));
    } finally {
      setBusy((b) => ({ ...b, [key]: false }));
    }
  }

  // Group by classification
  const overdue  = rows.filter((r) => classifyEntry(r) === 'overdue');
  const today    = rows.filter((r) => classifyEntry(r) === 'today');
  const upcoming = rows.filter((r) => classifyEntry(r) === 'upcoming');

  return (
    <div style={pageWrap}>
      {/* Page header */}
      <div style={pageHeader}>
        <div>
          <h1 style={pageTitle}>Pending Follow-ups</h1>
          <p style={pageSubtitle}>
            Unresolved follow-up log entries due within the next {DAYS_AHEAD} days, across all service engagements.
          </p>
        </div>
        <button type="button" onClick={fetchData} disabled={loading} style={btnRefresh}>
          {loading ? 'Refreshing…' : 'Refresh'}
        </button>
      </div>

      {error && <div style={errBox}>{error}</div>}

      {/* Summary KPIs */}
      {!loading && (
        <div style={kpiRow}>
          <KpiCard label="Overdue"  count={overdue.length}  color="#dc2626" bg="#FFF1F2" Icon={AlertTriangle} />
          <KpiCard label="Due Today" count={today.length}   color="#d97706" bg="#FFFBEB" Icon={Clock} />
          <KpiCard label="Upcoming" count={upcoming.length} color="#2563eb" bg="#EFF6FF" Icon={CalendarDays} />
        </div>
      )}

      {loading && <div style={loadingMsg}>Loading follow-ups…</div>}

      {!loading && rows.length === 0 && !error && (
        <div style={emptyState}>
          <CheckCircle2 size={32} color="#22c55e" />
          <div style={{ fontWeight: 700, color: '#0B1F3B', fontSize: 15 }}>All caught up!</div>
          <div style={{ color: '#94a3b8', fontSize: 13 }}>No pending follow-ups due in the next {DAYS_AHEAD} days.</div>
        </div>
      )}

      {/* Overdue group */}
      {overdue.length > 0 && (
        <Group
          title="Overdue"
          color="#dc2626"
          bg="#FFF1F2"
          icon={<AlertTriangle size={15} color="#dc2626" />}
          entries={overdue}
          onResolve={handleResolve}
          onRemind={handleRemind}
          busy={busy}
          actionMsg={actionMsg}
          navigate={navigate}
        />
      )}

      {/* Due today group */}
      {today.length > 0 && (
        <Group
          title="Due Today"
          color="#d97706"
          bg="#FFFBEB"
          icon={<Clock size={15} color="#d97706" />}
          entries={today}
          onResolve={handleResolve}
          onRemind={handleRemind}
          busy={busy}
          actionMsg={actionMsg}
          navigate={navigate}
        />
      )}

      {/* Upcoming group */}
      {upcoming.length > 0 && (
        <Group
          title={`Upcoming (next ${DAYS_AHEAD} days)`}
          color="#2563eb"
          bg="#EFF6FF"
          icon={<CalendarDays size={15} color="#2563eb" />}
          entries={upcoming}
          onResolve={handleResolve}
          onRemind={handleRemind}
          busy={busy}
          actionMsg={actionMsg}
          navigate={navigate}
        />
      )}
    </div>
  );
}

// ── KPI Card ──────────────────────────────────────────────────────────────────
function KpiCard({ label, count, color, bg, Icon }) {
  return (
    <div style={{ ...kpiCard, borderTop: `3px solid ${color}` }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <div style={{ fontSize: 12, fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: 6 }}>{label}</div>
          <div style={{ fontSize: 28, fontWeight: 700, color }}>{count}</div>
        </div>
        <div style={{ width: 36, height: 36, borderRadius: 8, background: bg, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Icon size={18} color={color} />
        </div>
      </div>
    </div>
  );
}

// ── Group section ─────────────────────────────────────────────────────────────
function Group({ title, color, bg, icon, entries, onResolve, onRemind, busy, actionMsg, navigate }) {
  return (
    <div style={groupCard}>
      <div style={{ ...groupHeader, background: bg }}>
        {icon}
        <span style={{ fontWeight: 700, fontSize: 14, color }}>{title}</span>
        <span style={{
          marginLeft: 6, fontSize: 12, fontWeight: 700,
          background: color, color: '#fff',
          borderRadius: 10, padding: '1px 8px',
        }}>{entries.length}</span>
      </div>
      <div style={{ overflowX: 'auto' }}>
        <table style={tableStyle}>
          <thead>
            <tr>
              {['Service', 'Client', 'Staff', 'Follow-up Date', 'Last Reminder', 'Note', 'Actions'].map((h) => (
                <th key={h} style={thStyle}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {entries.map((entry) => {
              const remindKey  = `remind-${entry.id}`;
              const resolveKey = `resolve-${entry.id}`;
              const canRemind  = entry.visibility === 'client' || entry.visibility === 'associate';
              return (
                <tr key={entry.id} style={{ borderBottom: '1px solid #F1F5F9' }}>
                  <td style={tdStyle}>
                    <div style={{ fontWeight: 600, fontSize: 13, color: '#0B1F3B' }}>
                      {entry.service_type}
                      {entry.financial_year && (
                        <span style={{ fontSize: 11, color: '#94a3b8', marginLeft: 6 }}>{entry.financial_year}</span>
                      )}
                    </div>
                    <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 2 }}>
                      <span style={statusPill}>{(entry.service_status || '').replace(/_/g, ' ')}</span>
                    </div>
                  </td>
                  <td style={tdStyle}>
                    <span style={{ fontSize: 13, color: '#334155' }}>
                      {entry.client_display_name || entry.client_name || '—'}
                    </span>
                  </td>
                  <td style={{ ...tdStyle, fontSize: 12, color: '#64748b' }}>
                    {entry.assignee_names || '—'}
                  </td>
                  <td style={tdStyle}>
                    <span style={{ fontSize: 13, fontWeight: 700, color }}>
                      {formatDate(entry.follow_up_date)}
                    </span>
                  </td>
                  <td style={{ ...tdStyle, fontSize: 12, color: '#94a3b8' }}>
                    {entry.reminder_sent_at ? formatDateTime(entry.reminder_sent_at) : '—'}
                  </td>
                  <td style={{ ...tdStyle, maxWidth: 220 }}>
                    <span style={{ fontSize: 12, color: '#334155', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
                      {entry.message}
                    </span>
                    {actionMsg[entry.id] && (
                      <div style={{ fontSize: 11, color: '#16a34a', marginTop: 3 }}>{actionMsg[entry.id]}</div>
                    )}
                  </td>
                  <td style={tdStyle}>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                      <button
                        type="button"
                        disabled={busy[resolveKey]}
                        onClick={() => onResolve(entry)}
                        style={actionBtn}
                        title="Mark resolved"
                      >
                        <CheckCircle2 size={13} />
                        Resolve
                      </button>
                      {canRemind && (
                        <button
                          type="button"
                          disabled={busy[remindKey]}
                          onClick={() => onRemind(entry)}
                          style={{ ...actionBtn, color: '#2563eb', borderColor: '#bfdbfe' }}
                          title="Send reminder to client"
                        >
                          <Bell size={13} />
                          Remind
                        </button>
                      )}
                      <button
                        type="button"
                        onClick={() => navigate(`/services/${entry.service_id}`)}
                        style={{ ...actionBtn, color: 'var(--portal-primary)', borderColor: 'rgba(var(--portal-primary-rgb),0.3)' }}
                        title="Open service"
                      >
                        <ExternalLink size={12} />
                        Open
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── Styles ────────────────────────────────────────────────────────────────────
const pageWrap = { padding: '24px', display: 'flex', flexDirection: 'column', gap: 20, background: 'var(--portal-bg)', minHeight: '100%' };
const pageHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 16 };
const pageTitle = { margin: 0, fontSize: 22, fontWeight: 700, color: '#0B1F3B' };
const pageSubtitle = { margin: '6px 0 0', fontSize: 13, color: '#64748b' };
const btnRefresh = {
  padding: '8px 18px', background: '#fff', border: '1px solid #E6E8F0',
  borderRadius: 8, cursor: 'pointer', fontSize: 13, fontWeight: 600, color: '#475569',
};
const errBox = {
  background: '#FFF1F2', border: '1px solid #fecdd3', borderRadius: 8,
  padding: '12px 16px', fontSize: 13, color: '#dc2626',
};
const kpiRow = { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 };
const kpiCard = {
  background: '#fff', borderRadius: 12, padding: '18px 20px',
  border: '1px solid #E6E8F0', boxShadow: '0 1px 4px rgba(0,0,0,0.05)',
};
const loadingMsg = { fontSize: 13, color: '#64748b', textAlign: 'center', padding: 24 };
const emptyState = {
  background: '#fff', borderRadius: 14, border: '1px solid #E6E8F0',
  padding: 40, display: 'flex', flexDirection: 'column',
  alignItems: 'center', gap: 12, textAlign: 'center',
};
const groupCard = { background: '#fff', borderRadius: 14, border: '1px solid #E6E8F0', overflow: 'hidden' };
const groupHeader = {
  display: 'flex', alignItems: 'center', gap: 8,
  padding: '12px 18px', borderBottom: '1px solid #E6E8F0',
};
const tableStyle = { width: '100%', borderCollapse: 'collapse' };
const thStyle = {
  textAlign: 'left', fontSize: 11, fontWeight: 700, color: '#64748b',
  textTransform: 'uppercase', letterSpacing: '0.04em',
  padding: '10px 14px', background: '#FAFBFD',
};
const tdStyle = { padding: '12px 14px', verticalAlign: 'top' };
const statusPill = {
  display: 'inline-block', padding: '1px 6px', borderRadius: 5,
  fontSize: 10, fontWeight: 700, background: '#F1F5F9', color: '#64748b',
  textTransform: 'capitalize',
};
const actionBtn = {
  display: 'inline-flex', alignItems: 'center', gap: 4,
  padding: '4px 10px', background: 'var(--portal-bg)', border: '1px solid #E6E8F0',
  borderRadius: 6, fontSize: 12, fontWeight: 600, cursor: 'pointer', color: '#475569',
};

