  };
}

/**
 * Format a contact/organization label with optional reference in brackets.
 * @param {string} displayName
 * @param {string} [reference]
 * @returns {string}
 */
export function formatEntityLabel(displayName, reference) {
  const name = String(displayName || '').trim() || 'Unknown';
  const ref = String(reference || '').trim();
  return ref ? `${name} (${ref})` : name;
}

/**
 * Renders displayName with optional muted (reference) suffix — matches CRM list styling.
 */
export function EntityNameWithReference({ displayName, reference, nameStyle = {}, refStyle = {} }) {
  const name = String(displayName || '').trim() || 'Unknown';
  const ref = String(reference || '').trim();
  return (
    <>
      <span style={nameStyle}>{name}</span>
      {ref ? (
        <span style={{ fontWeight: 400, color: '#64748b', marginLeft: 4, ...refStyle }}>
          ({ref})
        </span>
      ) : null}
    </>
  );
}

import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { buildLedgerDetailLine } from './ledgerTxnDetails';

const TXN_TYPE_LABELS = {
  invoice: 'Invoice',
  receipt: 'Receipt',
  tds_provisional: 'TDS (Prov.)',
  tds_final: 'TDS (Final)',
  rebate: 'Rebate',
  credit_note: 'Credit Note',
  opening_balance: 'Opening Bal.',
  brought_forward: 'B/F',
  payment_expense: 'On-behalf payment',
};

function txnTypeLabel(type) {
  return TXN_TYPE_LABELS[type] || String(type || '—');
}

function safeFilePart(s) {
  const t = String(s || 'Client')
    .replace(/[<>:"/\\|?*]/g, '')
    .replace(/\s+/g, '_')
    .trim()
    .slice(0, 72);
  return t || 'Client';
}

function formatInrPdf(n) {
  const x = Number(n);
  if (Number.isNaN(x)) return '—';
  // ASCII "Rs." — jsPDF Helvetica cannot render U+20B9 (₹).
  const amt = x.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  return `Rs.\u00A0${amt}`;
}

function ledgerRowDate(e) {
  const d = e.txnDate || e.date || '';
  if (typeof d !== 'string') return '—';
  const m = d.match(/^(\d{4}-\d{2}-\d{2})/);
  return m ? m[1] : d.slice(0, 10) || '—';
}

function numOrEmpty(v) {
  const n = Number(v);
  if (v == null || v === '' || Number.isNaN(n) || n === 0) return null;
  return n;
}

/**
 * Excel export: debit, credit, balance columns are true numeric cells (type `n`) so SUM etc. work.
 * Empty Dr/Cr cells are omitted (blank) rather than text placeholders.
 */
export function exportLedgerExcel({
  rows,
  clientName,
  fyLabel,
  dateFrom,
  dateTo,
  includeEntityColumn = false,
}) {
  if (!rows?.length) return;

  const ws = {};
  let r = 0;
  const set = (row, col, cell) => {
    const addr = XLSX.utils.encode_cell({ r: row, c: col });
    ws[addr] = cell;
  };

  set(r, 0, { t: 's', v: includeEntityColumn ? 'Group ledger statement' : 'Client ledger statement' });
  r += 1;
  set(r, 0, { t: 's', v: `${includeEntityColumn ? 'Group' : 'Client'}: ${clientName || '—'}` });
  r += 1;
  set(r, 0, { t: 's', v: `Financial year: ${fyLabel || '—'}` });
  r += 1;
  const rangeParts = [];
  if (dateFrom) rangeParts.push(`From ${dateFrom}`);
  if (dateTo) rangeParts.push(`To ${dateTo}`);
  if (rangeParts.length) {
    set(r, 0, { t: 's', v: rangeParts.join(' · ') });
    r += 1;
  }
  set(r, 0, { t: 's', v: `Generated: ${new Date().toISOString().slice(0, 10)}` });
  r += 2;

  const headerRow = r;
  const headers = ['Date'];
  if (includeEntityColumn) headers.push('Entity');
  headers.push('Entry type', 'Narration', 'Details', 'Billing profile', 'Debit (₹)', 'Credit (₹)', 'Balance (₹)');
  headers.forEach((h, c) => set(headerRow, c, { t: 's', v: h }));

  const numFmt = '#,##0.00';
  let dataRow = headerRow + 1;
  for (const e of rows) {
    const c0 = 0;
    const detail = buildLedgerDetailLine(e);
    let col = 0;
    set(dataRow, col, { t: 's', v: ledgerRowDate(e) });
    col += 1;
    if (includeEntityColumn) {
      set(dataRow, col, { t: 's', v: String(e.entityName || '').trim() || '—' });
      col += 1;
    }
    set(dataRow, col, { t: 's', v: txnTypeLabel(e.txnType) });
    set(dataRow, col + 1, { t: 's', v: String(e.narration ?? '').slice(0, 500) || '—' });
    set(dataRow, col + 2, { t: 's', v: String(detail || '').slice(0, 500) || '—' });
    set(dataRow, col + 3, { t: 's', v: String(e.billingProfileCode || '').trim() || '—' });

    const dr = numOrEmpty(e.debit);
    const cr = numOrEmpty(e.credit);
    if (dr != null) {
      set(dataRow, col + 4, { t: 'n', v: dr, z: numFmt });
    }
    if (cr != null) {
      set(dataRow, col + 5, { t: 'n', v: cr, z: numFmt });
    }
    const bal = Number(e.balance);
    set(dataRow, col + 6, {
      t: 'n',
      v: Number.isNaN(bal) ? 0 : bal,
      z: numFmt,
    });

    dataRow += 1;
  }

  const lastCol = headers.length - 1;
  const lastRow = dataRow - 1;
  ws['!ref'] = XLSX.utils.encode_range({
    s: { r: 0, c: 0 },
    e: { r: lastRow, c: lastCol },
  });
  ws['!cols'] = [
    { wch: 12 },
    ...(includeEntityColumn ? [{ wch: 22 }] : []),
    { wch: 14 },
    { wch: 28 },
    { wch: 40 },
    { wch: 16 },
    { wch: 14 },
    { wch: 14 },
    { wch: 16 },
  ];

  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Ledger');

  const fy = safeFilePart(fyLabel?.replace(/\s+/g, '_') || 'FY');
  const name = safeFilePart(clientName);
  XLSX.writeFile(wb, `Ledger_${name}_${fy}.xlsx`);
}

async function fetchLogoDataUrl(logoSrc) {
  if (!logoSrc) return null;
  try {
    const res = await fetch(logoSrc);
    if (!res.ok) return null;
    const blob = await res.blob();
    return await new Promise((resolve, reject) => {
      const fr = new FileReader();
      fr.onload = () => resolve(fr.result);
      fr.onerror = reject;
      fr.readAsDataURL(blob);
    });
  } catch {
    return null;
  }
}

/**
 * Client-ready PDF: logo, header block, and aligned ledger table.
 */
export async function exportLedgerPdf({
  rows,
  clientName,
  fyLabel,
  dateFrom,
  dateTo,
  logoSrc,
  includeEntityColumn = false,
}) {
  if (!rows?.length) return;

  const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
  const pageW = doc.internal.pageSize.getWidth();
  const margin = 14;
  const y0 = margin;
  let y = y0;

  const logoDataUrl = await fetchLogoDataUrl(logoSrc);
  const imgH = 14;
  const imgW = 40;
  let logoPlaced = false;
  if (logoDataUrl) {
    try {
      doc.addImage(logoDataUrl, 'PNG', margin, y0, imgW, imgH);
      logoPlaced = true;
    } catch {
      try {
        doc.addImage(logoDataUrl, 'JPEG', margin, y0, imgW, imgH);
        logoPlaced = true;
      } catch {
        /* skip logo if format unsupported */
      }
    }
  }

  const titleStr = 'Account ledger statement';
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(15);
  doc.setTextColor(15, 23, 42);
  const titleX = logoPlaced ? margin + imgW + 6 : margin;
  const titleH = doc.getTextDimensions(titleStr).h;
  const titleY = logoPlaced ? y0 + (imgH + titleH) / 2 - titleH * 0.2 : y0 + 5;
  doc.text(titleStr, titleX, titleY);
  y = y0 + (logoPlaced ? imgH : 8) + 8;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(10);
  doc.setTextColor(71, 85, 105);
  const meta = [
    `${includeEntityColumn ? 'Group' : 'Name'}: ${clientName || '—'}`,
    `Financial year: ${fyLabel || '—'}`,
  ];
  if (dateFrom || dateTo) {
    meta.push(`Period: ${dateFrom || '…'} to ${dateTo || '…'}`);
  }
  meta.push(`Generated: ${new Date().toLocaleString('en-IN', { dateStyle: 'medium', timeStyle: 'short' })}`);
  meta.forEach((line) => {
    doc.text(line, margin, y);
    y += 5;
  });
  y += 4;

  const body = rows.map((e) => {
    const row = [ledgerRowDate(e)];
    if (includeEntityColumn) row.push(String(e.entityName || '').trim() || '—');
    row.push(
      txnTypeLabel(e.txnType),
      String(e.narration ?? '').slice(0, 120) || '—',
      String(buildLedgerDetailLine(e) || '').slice(0, 160) || '—',
      String(e.billingProfileCode || '').trim() || '—',
      e.debit ? formatInrPdf(e.debit) : '—',
      e.credit ? formatInrPdf(e.credit) : '—',
      formatInrPdf(e.balance),
    );
    return row;
  });

  const pdfHead = [['Date']];
  if (includeEntityColumn) pdfHead[0].push('Entity');
  pdfHead[0].push('Entry type', 'Narration', 'Details', 'Billing profile', 'Debit (Rs.)', 'Credit (Rs.)', 'Balance (Rs.)');

  const colOffset = includeEntityColumn ? 1 : 0;
  autoTable(doc, {
    startY: y,
    head: pdfHead,
    body,
    theme: 'striped',
    styles: {
      font: 'helvetica',
      fontSize: 8,
      cellPadding: 2.5,
      lineColor: [226, 232, 240],
      lineWidth: 0.1,
      valign: 'middle',
    },
    headStyles: {
      fillColor: [37, 99, 235],
      textColor: 255,
      fontStyle: 'bold',
      halign: 'left',
    },
    columnStyles: {
      0: { cellWidth: 22 },
      [1 + colOffset]: { cellWidth: 24 },
      [2 + colOffset]: { cellWidth: 42 },
      [3 + colOffset]: { cellWidth: 48 },
      [4 + colOffset]: { cellWidth: 26 },
      [5 + colOffset]: {
        halign: 'right',
        cellWidth: 28,
        cellPadding: { left: 2.5, right: 4.5, top: 2.5, bottom: 2.5 },
      },
      [6 + colOffset]: {
        halign: 'right',
        cellWidth: 28,
        cellPadding: { left: 2.5, right: 4.5, top: 2.5, bottom: 2.5 },
      },
      [7 + colOffset]: {
        halign: 'right',
        cellWidth: 30,
        fontStyle: 'bold',
        cellPadding: { left: 2.5, right: 4.5, top: 2.5, bottom: 2.5 },
      },
    },
    alternateRowStyles: { fillColor: [248, 250, 252] },
    margin: { left: margin, right: margin },
    showHead: 'everyPage',
  });

  const pageCount = doc.internal.getNumberOfPages();
  const footY = doc.internal.pageSize.getHeight() - 8;
  for (let i = 1; i <= pageCount; i += 1) {
    doc.setPage(i);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(7);
    doc.setTextColor(148, 163, 184);
    doc.text(`Page ${i} of ${pageCount}`, pageW - margin, footY, { align: 'right' });
  }

  const fy = safeFilePart(fyLabel?.replace(/\s+/g, '_') || 'FY');
  const name = safeFilePart(clientName);
  doc.save(`Ledger_${name}_${fy}.pdf`);
}
